INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Define the economic problem.', 'The fundamental challenge of scarcity: human wants are infinite but resources are finite, so choices and trade-offs must be made about how to allocate them.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'List the three fundamental economic questions every society must answer.', 'What to produce? How to produce it? For whom to produce it? Different economic systems answer these in different ways.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Define opportunity cost and give one example.', 'The value of the next best alternative foregone when a choice is made. E.g. the opportunity cost of attending university for three years includes the salary that could have been earned working full-time.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Sketch a PPF and label efficient, inefficient and unattainable points.', 'A concave (bowed-out) curve. Points ON the curve are productively efficient; INSIDE are inefficient (unemployed resources); OUTSIDE are currently unattainable. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M25,30 Q170,30 185,115" fill="none" stroke="#1a73e8" stroke-width="2"/><circle cx="70" cy="55" r="3" fill="#16a34a"/><text x="76" y="52" font-size="8" fill="#16a34a">A</text><circle cx="70" cy="100" r="3" fill="#f59e0b"/><text x="76" y="102" font-size="8" fill="#f59e0b">B</text><circle cx="160" cy="50" r="3" fill="#dc2626"/><text x="166" y="48" font-size="8" fill="#dc2626">C</text><text x="80" y="132" font-size="9" fill="#0B1E3F">Consumer goods</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Capital</text></svg>', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Why is the PPF concave (bowed outwards)?', 'Because of the law of increasing opportunity cost: resources are not perfectly adaptable, so producing more of one good means giving up increasing amounts of the other.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Give two causes of an outward shift of the PPF.', 'More or better-quality factors of production (e.g. immigration, increased capital investment) and technological progress that raises productivity.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Name the four factors of production and their rewards.', 'Land (rent), labour (wages), capital (interest), enterprise (profit).', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Distinguish capital goods from consumer goods.', 'Capital goods are man-made resources used to produce other goods (machinery, factories). Consumer goods are bought for direct satisfaction (food, smartphones). More capital today means a larger PPF tomorrow.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Distinguish positive and normative statements with one example each.', 'Positive: objective and testable (e.g. "UK unemployment is 4.2%"). Normative: subjective value judgement (e.g. "Unemployment is too high"). Look for words like should, ought to, fair, unfair.', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'What is meant by ceteris paribus?', 'Latin for "all other things being equal" — an assumption that all other relevant variables are held constant while examining the effect of one variable. Essential for isolating relationships in economic models.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Compare a free-market and a command economy.', 'Free market: private ownership, prices set by supply and demand, profit motive (e.g. Hong Kong). Command: state ownership, central planning, social-welfare motive (e.g. North Korea). Most real economies are mixed.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'State the three functions of the price mechanism.', 'Signalling (prices convey information about scarcity), incentive (high prices encourage supply and discourage demand), and rationing (allocating scarce goods to those willing and able to pay).', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'Outline two advantages of specialisation and division of labour.', 'Higher productivity through repetition and skill development, and lower average costs from economies of scale and use of specialist machinery (Adam Smith''s pin factory example).', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.1', 'Economic Problem & Methodology', 'What is Hayek''s knowledge problem?', 'Friedrich Hayek argued that the information needed to allocate resources is dispersed across millions of individuals. Only the price mechanism can aggregate it; central planners cannot — a key critique of command economies.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Define demand and state the law of demand.', 'Demand is the quantity consumers are willing and able to buy at a given price. The law of demand: as price rises, quantity demanded falls (inverse relationship), ceteris paribus.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Give three reasons why the demand curve slopes downward.', 'Income effect (higher price reduces real purchasing power), substitution effect (consumers switch to cheaper alternatives), and diminishing marginal utility (each extra unit gives less satisfaction).', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Distinguish a movement along from a shift of the demand curve.', 'A movement along (extension/contraction) is caused by a change in the good''s own price. A shift (increase/decrease in demand) is caused by a non-price factor like income, tastes, or prices of related goods.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Sketch market equilibrium with consumer and producer surplus shaded.', 'D and S intersect at (Pe, Qe). Consumer surplus is the triangle below D and above Pe; producer surplus is above S and below Pe. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><polygon points="35,25 107,67 25,67" fill="#16a34a" fill-opacity="0.15"/><polygon points="35,110 107,67 25,67" fill="#1a73e8" fill-opacity="0.15"/><circle cx="107" cy="67" r="2.5" fill="#0B1E3F"/><line x1="25" y1="67" x2="107" y2="67" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><line x1="107" y1="67" x2="107" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="10" y="70" font-size="9" fill="#0B1E3F">Pe</text><text x="103" y="128" font-size="9" fill="#0B1E3F">Qe</text><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'How does the market eliminate excess supply?', 'When P > Pe, quantity supplied exceeds quantity demanded, so producers cut prices and reduce output. As price falls, Qd rises and Qs falls until equilibrium is restored.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Show on a diagram what happens when D shifts right while S is fixed.', 'New equilibrium has both higher price and higher quantity. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="2"/><text x="163" y="113" font-size="9" fill="#dc2626">D1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="172" y="98" font-size="9" fill="#dc2626">D2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><circle cx="92" cy="72" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="57" r="2.5" fill="#0B1E3F"/><line x1="92" y1="72" x2="118" y2="57" stroke="#64748b" stroke-width="0.8"/><text x="105" y="50" font-size="8" fill="#0B1E3F">→</text><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Define consumer surplus.', 'The difference between the maximum price a consumer is willing to pay and the price they actually pay. On a diagram, the triangle below the demand curve and above the market price.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'State the formula for PED and what it measures.', 'PED = % change in quantity demanded ÷ % change in price. It measures the responsiveness of quantity demanded to a change in the good''s own price; always negative.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Sketch and contrast price-elastic and price-inelastic demand.', 'Elastic: relatively flat (|PED| > 1). Inelastic: relatively steep (|PED| < 1). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="50" x2="180" y2="80" stroke="#16a34a" stroke-width="2"/><text x="160" y="45" font-size="8" fill="#16a34a">elastic</text><line x1="95" y1="20" x2="125" y2="115" stroke="#dc2626" stroke-width="2"/><text x="128" y="40" font-size="8" fill="#dc2626">inelastic</text><text x="10" y="65" font-size="9" fill="#0B1E3F">P</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Give four determinants of PED.', 'Availability of substitutes, whether the good is a necessity or luxury, proportion of income spent on it, time period (PED is more elastic in the long run), and degree of habit/addiction.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'If demand is price-inelastic, what should a firm do to raise revenue?', 'Raise the price. With inelastic demand, the price rise outweighs the small fall in Qd, so total revenue (P x Q) increases. Firms with elastic demand should cut prices instead.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Distinguish a normal good from an inferior good using YED.', 'YED = %ΔQd ÷ %ΔY. Normal goods have positive YED (demand rises with income); inferior goods have negative YED (demand falls as income rises, e.g. supermarket value brands, bus travel).', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'What does cross elasticity of demand (XED) tell you?', 'The relationship between two goods. Positive XED = substitutes (e.g. Coke and Pepsi). Negative XED = complements (e.g. printers and ink). The size shows the strength of the relationship.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'List three determinants of price elasticity of supply (PES).', 'Spare capacity, ability to store stocks, time period (longer = more elastic), factor mobility, and barriers to entry.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.2', 'Price Determination', 'Why are agricultural prices very volatile?', 'Both demand (food is a necessity) and short-run supply (fixed growing seasons) are price-inelastic, so a small supply shock — like the 2021 Brazilian frost that hit coffee — causes a large price swing.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Define productivity and give the formula for labour productivity.', 'Productivity is output per unit of input in a given time period. Labour productivity = total output ÷ number of workers (or labour hours). Higher productivity is the main driver of long-run living standards.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Distinguish the short run from the long run.', 'Short run: at least one factor of production is fixed (usually capital). Long run: all factors are variable and the firm can change its entire scale of production.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'State the law of diminishing marginal returns.', 'As successive units of a variable factor (e.g. labour) are added to a fixed factor (e.g. capital), the marginal product eventually falls. A short-run concept only.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Distinguish fixed costs and variable costs with examples.', 'Fixed costs do not vary with output (rent, insurance, business rates) and exist even at zero output. Variable costs do vary with output (raw materials, hourly wages, energy).', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Sketch the short-run cost curves (AFC, AVC, AC, MC).', 'AFC falls continuously; AVC and AC are U-shaped; MC cuts both AVC and AC at their minimums. The vertical gap between AC and AVC equals AFC. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q70,80 110,95 Q150,105 185,108" fill="none" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,2"/><text x="170" y="103" font-size="8" fill="#f59e0b">AFC</text><path d="M40,80 Q80,55 110,55 Q150,65 180,90" fill="none" stroke="#16a34a" stroke-width="1.5"/><text x="172" y="86" font-size="8" fill="#16a34a">AVC</text><path d="M40,55 Q80,35 115,40 Q150,50 180,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="172" y="71" font-size="8" fill="#1a73e8">AC</text><path d="M40,95 Q70,90 90,75 Q115,40 145,20" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="148" y="22" font-size="8" fill="#dc2626">MC</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Why does MC cross AC at the minimum point of AC?', 'When MC < AC, the next unit pulls the average down. When MC > AC, it pulls the average up. Therefore AC is at its minimum exactly where MC = AC — the same logic as exam grades.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Define economies of scale.', 'Cost advantages a firm gains as it increases its scale of production in the long run; long-run average cost falls. Causes the downward-sloping section of the LRAC curve.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Name four types of internal economies of scale.', 'Technical (specialised machinery), managerial (specialist managers), purchasing (bulk buying), financial (cheaper borrowing), marketing (advertising spread over more units), risk-bearing (diversification).', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Sketch the LRAC curve and label MES.', 'A U-shape: economies of scale (falling), then constant returns, then diseconomies (rising). MES is the lowest output where LRAC reaches its minimum. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,40 Q75,80 110,80 Q145,80 180,55" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="160" y="50" font-size="9" fill="#1a73e8">LRAC</text><line x1="110" y1="80" x2="110" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">MES</text><text x="40" y="105" font-size="7" fill="#16a34a">EoS</text><text x="140" y="40" font-size="7" fill="#dc2626">DoS</text><text x="100" y="138" font-size="9" fill="#0B1E3F">Q</text></svg>', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Distinguish diminishing marginal returns from decreasing returns to scale.', 'Diminishing returns: SHORT RUN, one factor fixed, explains U-shaped SR cost curves. Decreasing returns to scale: LONG RUN, all factors increase together, explains rising LRAC. Confusing them is heavily penalised.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Define normal and supernormal profit.', 'Normal profit: minimum return needed to keep a firm in the industry (TR = TC, included as a cost). Supernormal profit: profit above normal (TR > TC), which signals new firms to enter.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'State the profit-maximising rule.', 'A firm maximises profit by producing the output where MC = MR (with MC rising through MR). At any unit where MR > MC, profit rises by producing it; where MR < MC, profit falls.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'For a firm with market power, why does MR lie below AR?', 'To sell one extra unit it must lower the price on ALL units (not just the extra one). The marginal revenue from the next sale is therefore less than its price. For a linear demand curve, MR is twice as steep as AR.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'When should a loss-making firm shut down in the short run?', 'When AR < AVC. If revenue covers variable costs and contributes to fixed costs, the firm loses less by continuing. If AR < AVC it should shut down immediately.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.3', 'Production Costs & Revenue', 'Give two alternative objectives to profit maximisation.', 'Revenue maximisation (MR = 0) — managers'' bonuses linked to sales. Sales maximisation (AC = AR, normal-profit constraint) — building market share, e.g. Amazon. Also satisficing and survival.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'List the four main market structures from most to least competitive.', 'Perfect competition, monopolistic competition, oligopoly, monopoly. They differ in number of firms, barriers to entry, product differentiation, and price-setting power.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'State the assumptions of perfect competition.', 'Many small buyers and sellers, homogeneous product, perfect information, no barriers to entry/exit, firms are price takers, perfectly mobile factors, no externalities. Largely a theoretical benchmark.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Why are perfectly competitive firms price takers with horizontal demand curves?', 'Each firm is too small to influence the market price, and consumers can switch costlessly to identical products. So AR = MR = P, shown as a horizontal line at the market price.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Why does perfect competition deliver only normal profit in the long run?', 'No barriers to entry mean any supernormal profit attracts new firms. Market supply shifts right, price falls until P = AC (minimum) and supernormal profit is competed away.', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'In long-run perfect-competition equilibrium, which efficiencies are achieved?', 'Both: allocative efficiency (P = MC, value to consumers equals cost of last unit) and productive efficiency (output at minimum AC). Firms earn only normal profit.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'In UK competition law, what market share defines monopoly power?', 'A firm is classified as having monopoly power if it holds 25% or more of the market, the working definition used by the CMA. Pure (single-firm) monopoly is rare in practice.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Give four sources of monopoly power (barriers to entry).', 'Economies of scale / natural monopoly, patents and licences, brand loyalty and advertising, control of essential resources, network effects, sunk costs, predatory pricing.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Sketch the monopoly profit-max diagram with supernormal profit and DWL.', 'Profit max at MC=MR; price Pm read off AR=D above this output. Supernormal profit = (Pm - AC) x Qm; DWL is the triangle between Qm and the allocatively efficient Qc. <svg viewBox="0 0 200 150" width="180" height="135" style="display:block;margin:6px auto"><line x1="25" y1="125" x2="190" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="125" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="120" stroke="#16a34a" stroke-width="1.5"/><text x="183" y="123" font-size="8" fill="#16a34a">AR=D</text><line x1="35" y1="25" x2="107" y2="120" stroke="#f59e0b" stroke-width="1.5"/><text x="110" y="118" font-size="8" fill="#f59e0b">MR</text><path d="M35,100 Q70,90 100,75 Q130,55 165,30" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="167" y="32" font-size="8" fill="#dc2626">MC</text><path d="M35,80 Q80,55 110,52 Q150,60 175,80" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="178" y="84" font-size="8" fill="#1a73e8">AC</text><circle cx="80" cy="78" r="2" fill="#0B1E3F"/><line x1="80" y1="78" x2="80" y2="125" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="80" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="11" y="58" font-size="8" fill="#0B1E3F">Pm</text><text x="74" y="138" font-size="8" fill="#0B1E3F">Qm</text><rect x="35" y="55" width="45" height="13" fill="#16a34a" fill-opacity="0.2"/><polygon points="80,55 80,78 115,72" fill="#dc2626" fill-opacity="0.2"/></svg>', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Compared to perfect competition, what does a monopolist do?', 'Charges a higher price (Pm > Pc) and produces less output (Qm < Qc). This causes allocative inefficiency (P > MC) and a deadweight welfare loss; consumer surplus is transferred to producer surplus.', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Give one Schumpeterian argument FOR monopoly.', 'Supernormal profits fund R&D and innovation, driving "creative destruction." Without the prospect of monopoly profits — especially via patents — firms would have less incentive to develop new products.', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Define a natural monopoly.', 'A market where LRAC is still falling at the level of total market demand, so one firm can supply the whole market more cheaply than two. Examples: water, electricity transmission, railways. Usually regulated by Ofwat/Ofgem.', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Define oligopoly and its key feature.', 'A market dominated by a few large interdependent firms (e.g. UK supermarkets, mobile networks). Key feature is INTERDEPENDENCE — each firm''s decisions depend on rivals'' likely reactions, leading to game-theory style strategy.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Distinguish collusive and non-collusive oligopoly.', 'Collusive: firms cooperate to fix prices/output (cartel) — illegal under UK/EU law. Non-collusive: firms compete strategically. Tacit collusion (price leadership) is legal but suspicious.', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'What is the kinked demand curve theory?', 'Sweezy''s model: rivals match price cuts (so demand below P is inelastic) but ignore price rises (demand above P is elastic). A kink at the prevailing price explains why oligopoly prices are sticky.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.4', 'Competitive & Concentrated Markets', 'Give two examples of non-price competition in oligopoly.', 'Advertising and branding, product differentiation, loyalty schemes, customer service, packaging, R&D and innovation. Used because price wars are mutually destructive.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Define market failure.', 'When the free market fails to allocate resources efficiently, leading to a net welfare loss. The market equilibrium does not match the socially optimal outcome where MSB = MSC.', 1, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'List four main causes of market failure.', 'Externalities, public goods, merit/demerit goods (information failure), monopoly power, factor immobility, and inequality.', 2, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'State the formulae for MSC and MSB.', 'MSC = MPC + MEC (marginal private cost + marginal external cost). MSB = MPB + MEB. Social optimum is where MSC = MSB.', 3, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Sketch a negative production externality with welfare loss.', 'MSC lies above MPC. Market produces at Qm (where MPC=MPB) but social optimum is Q* (where MSC=MSB). Triangle between Q* and Qm is the welfare loss from overproduction. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="160" y="32" font-size="8" fill="#1a73e8">MPC</text><line x1="35" y1="80" x2="180" y2="20" stroke="#dc2626" stroke-width="1.8"/><text x="160" y="18" font-size="8" fill="#dc2626">MSC</text><line x1="35" y1="30" x2="180" y2="100" stroke="#16a34a" stroke-width="1.8"/><text x="160" y="105" font-size="8" fill="#16a34a">MSB</text><circle cx="115" cy="68" r="2" fill="#1a73e8"/><circle cx="100" cy="60" r="2" fill="#dc2626"/><line x1="115" y1="68" x2="115" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="60" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="110" y="128" font-size="8" fill="#1a73e8">Qm</text><text x="92" y="128" font-size="8" fill="#dc2626">Q*</text><polygon points="100,60 115,68 115,52" fill="#dc2626" fill-opacity="0.2"/></svg>', 4, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Give one example of a positive consumption externality.', 'Vaccination — the individual is protected (private benefit) but also can''t infect others, contributing to herd immunity. MSB > MPB, so the free market under-consumes; the NHS therefore provides vaccines free.', 5, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'State the two characteristics of a pure public good.', 'Non-excludable (cannot prevent non-payers using it) and non-rivalrous (one person''s use doesn''t reduce availability for others). Examples: defence, street lighting, lighthouses.', 6, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'What is the free-rider problem and why does it matter?', 'Because public goods are non-excludable, individuals can enjoy them without paying. Private firms cannot make a profit, so the good is not provided at all. Solved by compulsory taxation funding state provision.', 7, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Distinguish merit goods from public goods.', 'Merit goods are excludable and rivalrous — markets CAN provide them but provide too little (e.g. education, healthcare). Public goods CANNOT be provided by markets at all due to free riding. Different failures.', 8, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Distinguish adverse selection from moral hazard.', 'Adverse selection occurs BEFORE a transaction (hidden info, e.g. used-car "lemons"). Moral hazard occurs AFTER (changed behaviour, e.g. insured drivers being careless, banks taking risks if too-big-to-fail).', 9, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'How does an indirect tax correct a negative externality?', 'A specific or ad valorem tax raises producers'' costs, shifting MPC up to MSC. Output falls to the socially optimal Q*. Ideally the tax equals the marginal external cost — internalising the externality (Pigouvian tax).', 10, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Sketch the incidence of an indirect tax with inelastic demand.', 'Tax shifts S left to S+tax. Most of the tax is passed to consumers as higher prices because demand is inelastic. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="95" y1="20" x2="125" y2="115" stroke="#dc2626" stroke-width="1.8"/><text x="128" y="40" font-size="8" fill="#dc2626">D</text><line x1="35" y1="105" x2="180" y2="40" stroke="#1a73e8" stroke-width="1.8"/><text x="160" y="35" font-size="8" fill="#1a73e8">S</text><line x1="35" y1="85" x2="180" y2="20" stroke="#1a73e8" stroke-width="1.8" stroke-dasharray="4,3"/><text x="156" y="18" font-size="8" fill="#1a73e8">S+tax</text><circle cx="110" cy="68" r="2" fill="#0B1E3F"/><circle cx="105" cy="48" r="2" fill="#0B1E3F"/><line x1="25" y1="68" x2="110" y2="68" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="48" x2="105" y2="48" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="71" font-size="8" fill="#0B1E3F">P1</text><text x="10" y="51" font-size="8" fill="#0B1E3F">P2</text></svg>', 11, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'How does the UK Soft Drinks Industry Levy correct demerit-good consumption?', 'The 2018 sugar tax raises the cost of sugary drinks (a demerit good), shifting supply left and reducing consumption. Over half of manufacturers reformulated drinks to fall below the threshold; revenue funds school sports.', 12, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Sketch a price ceiling (max price) below equilibrium and its consequence.', 'Price capped below Pe creates excess demand (shortage), as Qd > Qs. Used to protect consumers (e.g. rent controls). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S</text><line x1="25" y1="85" x2="180" y2="85" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,3"/><text x="160" y="82" font-size="8" fill="#f59e0b">Pmax</text><circle cx="65" cy="85" r="2" fill="#1a73e8"/><circle cx="143" cy="85" r="2" fill="#dc2626"/><text x="60" y="100" font-size="7" fill="#1a73e8">Qs</text><text x="138" y="100" font-size="7" fill="#dc2626">Qd</text><text x="80" y="78" font-size="8" fill="#0B1E3F">shortage</text></svg>', 13, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'Explain how tradable pollution permits work.', 'Government caps total emissions and issues permits for that amount. Firms trade them — clean firms sell, dirty firms buy. Price reflects the cost of pollution and incentivises cleaner technology. The EU ETS is the largest example.', 14, 'alevel'),
  ('Economics', 'AQA', '3.1.5', 'Market Failure & Government Intervention', 'What is government failure?', 'When government intervention to correct market failure makes outcomes worse — through unintended consequences, regulatory capture, information gaps, political short-termism, or excessive bureaucracy. The cure can be worse than the disease.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'List the four main UK macroeconomic objectives.', 'Sustained economic growth (~2-2.5%), low and stable inflation (CPI 2% target), low unemployment, and a satisfactory balance of payments. Plus equity, sustainable public finances, and environmental goals.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Give two conflicts between macroeconomic objectives.', 'Growth vs inflation (rapid growth causes demand-pull inflation); growth vs current account (imports rise with income); low unemployment vs inflation (Phillips curve trade-off).', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define GDP and write the expenditure formula.', 'GDP is the total monetary value of all final goods and services produced within a country in a period. GDP = C + I + G + (X - M).', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Distinguish nominal from real GDP.', 'Nominal GDP is measured at current prices and rises with inflation alone. Real GDP is adjusted for inflation (constant base-year prices) and reflects the true change in output. Real GDP is the meaningful measure of growth.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Sketch the economic cycle around trend GDP.', 'Actual GDP fluctuates around the rising trend line through boom (peak), recession (contraction), trough (slump), and recovery. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="30" y1="100" x2="185" y2="35" stroke="#64748b" stroke-width="1.5" stroke-dasharray="4,3"/><text x="160" y="30" font-size="8" fill="#64748b">trend</text><path d="M30,95 Q55,55 80,75 Q105,100 130,70 Q155,40 185,55" fill="none" stroke="#1a73e8" stroke-width="1.8"/><text x="55" y="55" font-size="7" fill="#16a34a">boom</text><text x="92" y="100" font-size="7" fill="#dc2626">recession</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Time</text></svg>', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define a recession technically.', 'Two consecutive quarters of negative real GDP growth. Typically associated with rising unemployment, falling investment, and lower confidence — e.g. UK GDP fell 9.7% in 2020.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Give three limitations of GDP as a measure of living standards.', 'Hides income inequality; excludes shadow/non-marketed work (housework, voluntary); ignores environmental damage; doesn''t capture quality, leisure, or composition of output; PPP needed for international comparison.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'What does HDI measure beyond GDP?', 'The Human Development Index combines life expectancy, mean and expected years of schooling, and GNI per capita (PPP). Captures health and education outcomes, not just output.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define inflation, deflation and disinflation.', 'Inflation: sustained rise in the average price level. Deflation: sustained fall. Disinflation: a fall in the rate of inflation (prices still rising, but more slowly, e.g. 10% to 5%).', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Outline how CPI is calculated.', 'A representative basket of ~700 goods is selected and weighted by household spending shares. ONS collects ~180,000 prices monthly. The weighted average is expressed as an index relative to a base year of 100.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Give two reasons CPI may be a poor measure for individual households.', 'It is a national average, hiding different inflation rates for pensioners, students, families etc. It excludes mortgage interest, may have substitution bias, and quality adjustments are imprecise.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Distinguish the Claimant Count from the ILO/LFS unemployment measure.', 'Claimant Count: those claiming unemployment-related benefits (admin records, monthly). ILO/LFS: those without a job who actively sought work in the last 4 weeks and can start within 2 (survey, internationally comparable).', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'List four types of unemployment.', 'Frictional (between jobs), structural (mismatch of skills/location), cyclical / demand-deficient (recession), seasonal, real-wage (classical, wage above market-clearing).', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.1', 'Measurement of Macroeconomic Performance', 'Define the current account of the balance of payments.', 'Records international trade in goods and services, primary income (wages, investment income) and secondary income (transfers). The UK typically runs a current account deficit, financed by capital and financial inflows.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List the injections and withdrawals in the circular flow.', 'Injections (J): Investment, Government spending, eXports. Withdrawals (W): Savings, Taxation, iMports. Equilibrium when J = W; if J > W, national income rises.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Write the AD formula and the largest component in the UK.', 'AD = C + I + G + (X - M). Consumption (C) is the largest, around 60% of UK AD.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Give three reasons the AD curve slopes downward.', 'Real-balance (wealth) effect — higher PL erodes savings; interest-rate effect — higher PL raises money demand and rates, cutting C and I; international competitiveness — higher PL hits net exports.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Sketch AD/AS equilibrium with an outward AD shift.', 'AD shifts right along upward-sloping SRAS, raising both real output and price level. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,100 Q90,75 150,40" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="153" y="38" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="70" y1="25" x2="185" y2="105" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="100" font-size="8" fill="#dc2626">AD2</text><circle cx="86" cy="80" r="2" fill="#0B1E3F"/><circle cx="115" cy="60" r="2" fill="#0B1E3F"/><text x="100" y="130" font-size="9" fill="#0B1E3F">Y</text><text x="10" y="65" font-size="9" fill="#0B1E3F">PL</text></svg>', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Define MPC and MPS and state the relationship.', 'MPC = ΔC/ΔY (fraction of extra income spent). MPS = ΔS/ΔY (fraction saved). In a simple closed economy with no tax, MPC + MPS = 1.', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List three factors that increase consumption.', 'Lower interest rates, rising consumer confidence, rising house and asset prices (wealth effect), tax cuts, easier credit availability.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'What is the accelerator effect?', 'A change in the rate of growth of demand causes a magnified change in investment. Rising consumer demand encourages firms to invest in new capacity; falling demand causes them to cut investment sharply.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Why is the SRAS curve upward-sloping?', 'In the short run, wages and other input costs are sticky. A higher price level raises profit margins, incentivising firms to expand output.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Give three causes of an SRAS shift left.', 'Rising wages, rising raw material/commodity/energy prices, exchange rate depreciation (imported inputs more expensive), higher indirect taxes, supply shocks (war, pandemic).', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Sketch the Classical (vertical) LRAS curve.', 'LRAS is vertical at the full-employment output Yfe — long-run output is determined by productive capacity, not the price level. Shifts in AD only change PL. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="120" y1="20" x2="120" y2="115" stroke="#16a34a" stroke-width="2"/><text x="123" y="22" font-size="9" fill="#16a34a">LRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><text x="115" y="128" font-size="8" fill="#0B1E3F">Yfe</text><text x="10" y="65" font-size="9" fill="#0B1E3F">PL</text></svg>', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'Contrast Keynesian and Classical views of LRAS.', 'Classical: vertical LRAS — economy self-corrects to full employment via flexible wages/prices. Keynesian: LRAS has horizontal section (spare capacity), upward-sloping middle, then vertical at full capacity — wages and prices are sticky downward.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'List three causes of an LRAS shift right.', 'More/better factors of production (immigration, capital investment, education), technological progress, improved productivity, supply-side reforms, falling natural rate of unemployment.', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'State the multiplier formula and what it represents.', 'k = 1/(1 - MPC) or k = 1/MPW. An initial injection (e.g. £1bn G) leads to a final increase in GDP of k x £1bn as spending circulates. A larger MPC = larger multiplier.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.2', 'How the Macroeconomy Works', 'If MPC = 0.8, what is the multiplier?', 'k = 1/(1 - 0.8) = 1/0.2 = 5. A £10bn injection raises real GDP by £50bn in equilibrium (assuming spare capacity).', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Distinguish actual from potential growth.', 'Actual growth: increase in real GDP (movement towards/along the PPF, AD shifts right). Potential growth: increase in productive capacity (PPF or LRAS shifts right). Sustainable growth requires both.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Define the output gap.', 'The difference between actual and potential GDP. Positive output gap: actual > potential (overheating, inflation pressure). Negative output gap: spare capacity, low inflation/deflation pressure.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give three benefits of economic growth.', 'Higher living standards (more real income per head), lower unemployment (derived demand for labour), higher tax revenue (fiscal dividend), reduced poverty, higher business confidence.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give three costs of economic growth.', 'Environmental degradation (pollution, resource depletion), demand-pull inflation if AD outpaces capacity, rising inequality, current account deterioration (more imports), longer working hours.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Sketch demand-pull inflation on AD/AS.', 'AD shifts right near full capacity; mainly the price level rises with little extra output. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="65" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="75" x2="100" y2="75" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="125" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="8" y="78" font-size="8" fill="#0B1E3F">PL1</text><text x="8" y="53" font-size="8" fill="#0B1E3F">PL2</text></svg>', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'What causes cost-push inflation? Sketch the diagram.', 'A leftward shift in SRAS (e.g. from 2022 gas prices) raises the price level while reducing output — stagflation. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q155,20 170,15" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="172" y="17" font-size="8" fill="#1a73e8">SRAS1</text><path d="M35,90 Q80,60 115,30 Q135,15 145,10" fill="none" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="100" y="22" font-size="8" fill="#1a73e8">SRAS2</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><circle cx="115" cy="65" r="2" fill="#0B1E3F"/><circle cx="93" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="65" x2="115" y2="65" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="93" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/></svg>', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Define stagflation.', 'Simultaneously high inflation AND stagnant or falling output (low growth, often rising unemployment). Caused by adverse supply shocks shifting SRAS left — e.g. UK 2022, world economy in the 1970s oil crisis.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give three consequences of high inflation.', 'Erodes real purchasing power (worst for those on fixed incomes), menu and shoe-leather costs, reduced international competitiveness, redistributes from savers to borrowers, fiscal drag, possible wage-price spiral.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Why do central banks fear deflation?', 'Consumers postpone spending (waiting for lower prices) → AD falls further. The real value of debt rises → defaults. Nominal rates hit zero (liquidity trap) so monetary policy is impotent. Japan''s "lost decades" illustrate this.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Sketch the short- and long-run Phillips curves.', 'SRPC slopes down (trade-off between unemployment and inflation). LRPC is vertical at the natural rate of unemployment (NRU). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,30 Q70,55 110,90 Q140,108 180,112" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="160" y="105" font-size="8" fill="#1a73e8">SRPC</text><line x1="115" y1="20" x2="115" y2="115" stroke="#dc2626" stroke-width="2"/><text x="118" y="22" font-size="8" fill="#dc2626">LRPC</text><text x="105" y="128" font-size="8" fill="#dc2626">NRU</text><text x="100" y="138" font-size="9" fill="#0B1E3F">U%</text><text x="6" y="65" font-size="9" fill="#0B1E3F">π%</text></svg>', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Why is the long-run Phillips curve vertical?', 'Friedman/Phelps: any short-run trade-off depends on expectations. As workers learn that policy has raised inflation, they demand higher wages — SRPC shifts up. In the long run, unemployment returns to the NRU regardless of inflation.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Define the natural rate of unemployment (NRU).', 'The unemployment that exists when the labour market is in equilibrium — the sum of frictional and structural unemployment. Cyclical unemployment is zero. Cannot be reduced by demand-side policy alone.', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'Give three consequences of unemployment.', 'Lost output (economy inside PPF), lost tax revenue and higher benefit spending (fiscal cost), deskilling (hysteresis), poverty and inequality, social/health problems, lower aggregate demand.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.3', 'Economic Performance', 'What is hysteresis in labour markets?', 'The tendency for unemployment to persist after the original cause has passed. Long-term unemployed workers lose skills, motivation, and networks — raising the NRU. Justifies aggressive demand-side action in deep recessions.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'List four key functions of financial markets.', 'Facilitating saving, channelling funds from savers to borrowers (intermediation), providing liquidity, pricing risk, enabling firms to raise capital (shares/bonds), and facilitating international trade via FX.', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Distinguish money markets from capital markets.', 'Money markets trade short-term debt (under 1 year) — Treasury bills, interbank loans. Capital markets trade long-term debt (bonds) and equity (shares). Primary = new issues; secondary = existing securities.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'State the four functions of money.', 'Medium of exchange (eliminates barter), store of value (holds purchasing power over time), unit of account (common measure of value), and standard of deferred payment (enables credit/contracts).', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'How do commercial banks create money?', 'When a bank makes a loan it credits a new deposit in the borrower''s account. As that money is spent and re-deposited, the cycle repeats — most money in the economy is bank deposits, not central-bank cash.', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Sketch the money market with an increase in money supply.', 'MS is vertical (set by the BoE). MD slopes down (liquidity preference). MS shifts right → equilibrium interest rate falls. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="90" y1="20" x2="90" y2="115" stroke="#1a73e8" stroke-width="2"/><text x="80" y="18" font-size="8" fill="#1a73e8">MS1</text><line x1="135" y1="20" x2="135" y2="115" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="138" y="18" font-size="8" fill="#1a73e8">MS2</text><line x1="35" y1="30" x2="180" y2="105" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="108" font-size="8" fill="#dc2626">MD</text><circle cx="90" cy="58" r="2" fill="#0B1E3F"/><circle cx="135" cy="81" r="2" fill="#0B1E3F"/><line x1="25" y1="58" x2="90" y2="58" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="81" x2="135" y2="81" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="61" font-size="8" fill="#0B1E3F">r1</text><text x="10" y="84" font-size="8" fill="#0B1E3F">r2</text></svg>', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'State Keynes'' three motives for holding money.', 'Transactions (everyday spending — depends on income), precautionary (buffer for emergencies — depends on income/uncertainty), speculative (anticipating bond price changes — inversely related to the interest rate).', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'What is the liquidity trap?', 'When interest rates are at or near zero, MD becomes perfectly elastic — extra money is hoarded rather than spent or used to buy bonds. Conventional monetary policy becomes ineffective; QE may be needed.', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Why was the Bank of England granted independence in 1997?', 'To remove political short-termism (the political business cycle), improve credibility and anchor inflation expectations, and align with international norms. The MPC sets Bank Rate to meet the 2% CPI target.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Outline the transmission mechanism of a Bank Rate cut.', 'Lower Bank Rate → cheaper borrowing and lower returns on saving → C and I rise; weaker pound → exports rise, imports fall; asset prices rise (wealth effect). All increase AD and the price level.', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Define quantitative easing (QE).', 'Unconventional monetary policy where the central bank creates electronic reserves to buy government bonds and other assets. This raises bond prices, lowers long-term yields, and boosts liquidity, lending and AD.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Give two side effects of prolonged QE.', 'Inflated asset prices (housing, equities) which worsens wealth inequality; risks of asset bubbles; difficulty unwinding (quantitative tightening); some loss of central-bank independence credibility.', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'What is the relationship between bond prices and interest rates?', 'Inverse. When market rates rise, existing bonds with lower coupons become less attractive, so their price falls. When rates fall, existing bonds become more attractive and their price rises.', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Explain why banks failed during the 2008 financial crisis.', 'Excessive risk-taking, sub-prime mortgage lending, complex derivatives (CDOs) hiding risk, high leverage, moral hazard ("too big to fail"), and inadequate regulation. The UK government spent ~£137bn rescuing banks.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'Give three post-2008 financial regulations.', 'Higher capital requirements (Basel III), separation of retail and investment banking (UK ring-fencing under Vickers), stress testing by the BoE, the FPC for macroprudential oversight, and the PRA for bank supervision.', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.4', 'Financial Markets & Monetary Policy', 'What does the Bank of England do as "lender of last resort"?', 'Provides emergency liquidity to solvent commercial banks facing temporary cash shortages, preventing bank runs and systemic collapse. Critical during the 2007-08 Northern Rock crisis.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Define fiscal policy and name its two main instruments.', 'The use of government spending (G) and taxation (T) to influence AD and macroeconomic objectives. Set by the Chancellor in the Budget; affects AD directly (G) and indirectly via C and I (T).', 1, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish current spending, capital spending, and transfer payments.', 'Current: day-to-day costs (NHS wages, school running costs). Capital: long-lived assets (hospitals, HS2). Transfers: payments without goods/services in return (pensions, Universal Credit) — not in GDP but boost C.', 2, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish progressive, regressive and proportional taxes.', 'Progressive: % paid rises with income (UK income tax). Regressive: % paid falls as income rises (VAT — flat rate but lower earners spend a higher share). Proportional: constant % regardless of income.', 3, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'List Adam Smith''s four canons of taxation.', 'Equity (fairness, ability to pay), economy (low collection costs), convenience (easy to pay), certainty (clear rules). Modern additions: flexibility and efficiency (low distortion).', 4, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish a budget deficit from the national debt.', 'Budget deficit: a flow — government spending exceeds tax in a year (G > T). National debt: a stock — total accumulated past borrowing. UK debt exceeded 100% of GDP after COVID.', 5, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish cyclical from structural deficits.', 'Cyclical: caused by the economic cycle — disappears when growth returns. Structural: persists even at full employment, requiring deliberate cuts or tax rises. Cutting cyclical deficits in a recession can deepen it.', 6, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Sketch expansionary fiscal policy on AD/AS.', 'Increase in G or cut in T shifts AD right; real GDP rises and PL increases. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="70" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="75" x2="100" y2="75" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="75" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="125" y1="50" x2="125" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="95" y="128" font-size="7" fill="#0B1E3F">Y1</text><text x="120" y="128" font-size="7" fill="#0B1E3F">Y2</text></svg>', 7, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Give two examples of automatic stabilisers.', 'Progressive income tax (takes more in booms, less in recessions) and means-tested welfare benefits (rise in recessions as unemployment increases, fall in booms). They dampen the cycle without explicit policy decisions.', 8, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish demand-side from supply-side policies.', 'Demand-side: shift AD (fiscal and monetary policy). Supply-side: shift LRAS by raising productive potential (education, training, deregulation, infrastructure, tax incentives).', 9, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'List four supply-side policies.', 'Investment in education and training, infrastructure (HS2, broadband), reducing income tax to incentivise work, cutting corporation tax to encourage investment, deregulating labour/product markets, privatisation.', 10, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Distinguish interventionist from market-based supply-side policies.', 'Interventionist: government action to fix market failures (state spending on training, infrastructure, R&D grants). Market-based: reducing state involvement (tax cuts, deregulation, privatisation, weaker trade unions).', 11, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Sketch a successful supply-side policy on AD/AS.', 'LRAS shifts right; output rises and the price level falls — non-inflationary growth. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="100" y1="20" x2="100" y2="115" stroke="#16a34a" stroke-width="2"/><text x="78" y="22" font-size="8" fill="#16a34a">LRAS1</text><line x1="135" y1="20" x2="135" y2="115" stroke="#16a34a" stroke-width="2" stroke-dasharray="4,3"/><text x="138" y="22" font-size="8" fill="#16a34a">LRAS2</text><line x1="40" y1="30" x2="170" y2="115" stroke="#dc2626" stroke-width="1.8"/><text x="173" y="113" font-size="8" fill="#dc2626">AD</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="135" cy="98" r="2" fill="#0B1E3F"/><line x1="25" y1="75" x2="100" y2="75" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="98" x2="135" y2="98" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="8" y="78" font-size="8" fill="#0B1E3F">PL1</text><text x="8" y="101" font-size="8" fill="#0B1E3F">PL2</text></svg>', 12, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Give two evaluation points on supply-side policies.', 'Long time lags (education takes years to feed through), high opportunity cost, may worsen inequality (e.g. tax cuts for high earners), success uncertain — many supply-side reforms (UK 1980s) had mixed results.', 13, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Define crowding out.', 'When increased government borrowing pushes up interest rates, reducing private investment and consumption. Most likely when the economy is near full capacity; less of a concern in deep recessions with spare savings.', 14, 'alevel'),
  ('Economics', 'AQA', '3.2.5', 'Fiscal & Supply-Side Policies', 'Compare the UK''s 2010-15 austerity with the 2020-21 COVID stimulus.', 'Austerity: contractionary — VAT rose to 20%, public-sector pay frozen, welfare cuts; deficit fell but recovery was slow. COVID stimulus: expansionary — £70bn furlough, business grants, Eat Out to Help Out; debt rose past 100% of GDP but mass unemployment was avoided.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Distinguish positive from normative statements with one example each.', 'Positive: an objective, testable claim (e.g. "UK CPI inflation was 4.2% in 2024"). Normative: a value judgement (e.g. "the government should reduce inequality"). Words like should, ought, fair signal normative.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Define opportunity cost.', 'The value of the next best alternative foregone when a choice is made. E.g. £50bn spent on HS2 has an opportunity cost equal to the next best use, such as new hospitals or schools.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Sketch a PPF and label efficient, inefficient and unattainable points.', 'A concave (bowed-out) curve. Points ON the curve are productively efficient; INSIDE are inefficient (spare capacity); OUTSIDE are currently unattainable. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,25 Q175,25 180,115" fill="none" stroke="#1a73e8" stroke-width="2"/><circle cx="70" cy="55" r="3" fill="#16a34a"/><text x="76" y="52" font-size="8" fill="#16a34a">A</text><circle cx="70" cy="100" r="3" fill="#f59e0b"/><text x="76" y="102" font-size="8" fill="#f59e0b">B</text><circle cx="160" cy="50" r="3" fill="#dc2626"/><text x="166" y="48" font-size="8" fill="#dc2626">C</text><text x="80" y="132" font-size="9" fill="#0B1E3F">Consumer goods</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Capital</text></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Why is the PPF concave (bowed outwards)?', 'Because of the law of increasing opportunity cost: factors of production are not perfectly adaptable between uses, so producing more of one good means giving up increasingly more of the other.', 4, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Name the four factors of production and their factor rewards.', 'Land — rent. Labour — wages. Capital — interest/profit. Enterprise — profit. Capital includes physical (machinery) and human (skills, education) capital.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Outline two advantages of specialisation and division of labour.', 'Higher productivity through repetition and skill development; lower unit costs from economies of scale and use of specialist machinery. Adam Smith''s pin factory raised output from 20 to 4,800 pins per worker per day.', 6, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Sketch supply and demand and show the effect of a rightward shift in demand.', 'New equilibrium at higher price and higher quantity. Driven by non-price factors like rising income or tastes. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="2"/><text x="163" y="113" font-size="9" fill="#dc2626">D1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="172" y="98" font-size="9" fill="#dc2626">D2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><circle cx="92" cy="72" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="57" r="2.5" fill="#0B1E3F"/><line x1="92" y1="72" x2="118" y2="57" stroke="#64748b" stroke-width="0.8"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 7, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'State the three functions of the price mechanism.', 'Signalling (prices convey information about scarcity), incentive (high prices encourage supply and discourage demand), and rationing (allocating scarce goods to those willing and able to pay).', 8, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Sketch market equilibrium with consumer and producer surplus.', 'Consumer surplus is the triangle below D and above Pe; producer surplus is above S and below Pe. Together they form total welfare. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><polygon points="35,25 107,67 25,67" fill="#16a34a" fill-opacity="0.18"/><text x="50" y="55" font-size="7" fill="#16a34a">CS</text><polygon points="35,110 107,67 25,67" fill="#1a73e8" fill-opacity="0.18"/><text x="50" y="92" font-size="7" fill="#1a73e8">PS</text><circle cx="107" cy="67" r="2.5" fill="#0B1E3F"/><line x1="25" y1="67" x2="107" y2="67" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="107" y1="67" x2="107" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="70" font-size="9" fill="#0B1E3F">Pe</text><text x="103" y="128" font-size="9" fill="#0B1E3F">Qe</text></svg>', 9, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'State the formula for PED and how the sign is interpreted.', 'PED = % change in quantity demanded ÷ % change in price. Almost always negative due to the law of demand; we usually compare absolute values. |PED| > 1 = elastic, < 1 = inelastic.', 10, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Sketch and contrast price-elastic and price-inelastic demand.', 'Elastic: relatively flat (|PED| > 1, e.g. branded clothing). Inelastic: relatively steep (|PED| < 1, e.g. petrol, insulin). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="50" x2="180" y2="80" stroke="#16a34a" stroke-width="2"/><text x="155" y="45" font-size="8" fill="#16a34a">elastic</text><line x1="95" y1="20" x2="125" y2="115" stroke="#dc2626" stroke-width="2"/><text x="128" y="40" font-size="8" fill="#dc2626">inelastic</text><text x="10" y="65" font-size="9" fill="#0B1E3F">P</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 11, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'List four determinants of PED.', 'Availability of substitutes (most important), necessity vs luxury, proportion of income spent, time period (more elastic in long run), brand loyalty/addiction, and how narrowly the market is defined.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'If demand is price-inelastic, how should a firm change price to raise revenue?', 'Raise price. With |PED| < 1, the proportional fall in Q is smaller than the rise in P, so total revenue (P × Q) increases. Why luxury brands rarely discount and governments tax petrol/cigarettes heavily.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'Distinguish normal and inferior goods using YED.', 'YED = %ΔQd ÷ %ΔY. Normal goods have positive YED (demand rises with income); luxuries YED > 1, necessities 0 < YED < 1. Inferior goods have negative YED (e.g. value-brand food, bus travel — demand falls as income rises).', 14, 'alevel'),
  ('Economics', 'Edexcel A', '1.1', 'Nature of Economics & Markets', 'What does cross elasticity of demand (XED) tell you?', 'The relationship between two goods. Positive XED = substitutes (Coke & Pepsi, Uber & taxis). Negative XED = complements (printers & ink, cars & petrol). Magnitude shows the strength of the relationship.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Define market failure.', 'When the free market fails to allocate resources efficiently, so the equilibrium does not maximise social welfare. The market outcome diverges from the social optimum where MSB = MSC.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'State the formulae for social cost and social benefit.', 'Social Cost = Private Cost + External Cost. Social Benefit = Private Benefit + External Benefit. The social optimum is at MSC = MSB. Externalities cause divergence between private and social.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Sketch a negative production externality with welfare loss.', 'MSC sits above MPC. Free market produces at Qm (MPC=D); social optimum is Q* (MSC=D). Triangle between Q* and Qm above D is the welfare loss from over-production. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="32" font-size="8" fill="#1a73e8">MPC</text><line x1="35" y1="80" x2="180" y2="20" stroke="#dc2626" stroke-width="1.8"/><text x="158" y="18" font-size="8" fill="#dc2626">MSC</text><line x1="35" y1="30" x2="180" y2="100" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="105" font-size="8" fill="#16a34a">D=MSB</text><circle cx="115" cy="68" r="2" fill="#1a73e8"/><circle cx="100" cy="60" r="2" fill="#dc2626"/><line x1="115" y1="68" x2="115" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="60" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="110" y="128" font-size="8" fill="#1a73e8">Qm</text><text x="92" y="128" font-size="8" fill="#dc2626">Q*</text><polygon points="100,60 115,68 115,52" fill="#dc2626" fill-opacity="0.25"/></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Sketch a positive consumption externality (e.g. vaccination).', 'MSB lies above MPB. Market output Qm is below the social optimum Q*; the good is under-consumed. Welfare loss triangle between Qm and Q*. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="30" stroke="#dc2626" stroke-width="1.8"/><text x="155" y="28" font-size="8" fill="#dc2626">S=MSC</text><line x1="35" y1="35" x2="180" y2="105" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="110" font-size="8" fill="#1a73e8">MPB</text><line x1="35" y1="20" x2="180" y2="90" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="95" font-size="8" fill="#16a34a">MSB</text><circle cx="100" cy="65" r="2" fill="#1a73e8"/><circle cx="120" cy="68" r="2" fill="#16a34a"/><line x1="100" y1="65" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="120" y1="68" x2="120" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="92" y="128" font-size="8" fill="#1a73e8">Qm</text><text x="115" y="128" font-size="8" fill="#16a34a">Q*</text><polygon points="100,65 120,68 100,52" fill="#16a34a" fill-opacity="0.25"/></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'State the two characteristics of a pure public good.', 'Non-excludable (cannot prevent non-payers using it) and non-rival (one person''s use does not reduce availability for others). Examples: national defence, street lighting, lighthouses.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'What is the free-rider problem?', 'Because public goods are non-excludable, individuals can enjoy them without paying. Private firms cannot generate revenue, so the good is not provided at all — complete market failure. Solved by tax-funded state provision.', 6, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Distinguish merit goods from public goods.', 'Merit goods (education, healthcare) are excludable and rival — markets provide them but too little. Public goods are non-excludable and non-rival — markets provide none. Different failures, different solutions.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Distinguish adverse selection from moral hazard.', 'Adverse selection occurs BEFORE a transaction (hidden information — Akerlof''s "lemons" used-car market). Moral hazard occurs AFTER (changed behaviour — insured drivers being careless, "too big to fail" banks).', 8, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Sketch the incidence of an indirect tax (specific tax).', 'Tax shifts S up by the tax amount (parallel shift). Price rises from P1 to P2, quantity falls. Vertical gap between S and S+tax is the tax. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="105" x2="180" y2="40" stroke="#1a73e8" stroke-width="1.8"/><text x="160" y="38" font-size="8" fill="#1a73e8">S</text><line x1="35" y1="85" x2="180" y2="20" stroke="#1a73e8" stroke-width="1.8" stroke-dasharray="4,3"/><text x="155" y="18" font-size="8" fill="#1a73e8">S+tax</text><circle cx="110" cy="68" r="2" fill="#0B1E3F"/><circle cx="100" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="68" x2="110" y2="68" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="100" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="71" font-size="8" fill="#0B1E3F">P1</text><text x="10" y="53" font-size="8" fill="#0B1E3F">P2</text></svg>', 9, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'How did the UK Soft Drinks Industry Levy (2018) change the market?', 'Drinks with > 8g sugar per 100ml taxed at 24p/litre. By 2020, average sugar content had fallen ~44% as Lucozade, Ribena and Fanta reformulated. Raises around £340m/year, ring-fenced for school sports.', 10, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Sketch a maximum price (price ceiling) below equilibrium.', 'Pmax sits below Pe, creating excess demand (Qd > Qs) — a shortage. Used in rent controls. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S</text><line x1="25" y1="85" x2="180" y2="85" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,3"/><text x="160" y="82" font-size="8" fill="#f59e0b">Pmax</text><circle cx="65" cy="85" r="2" fill="#1a73e8"/><circle cx="143" cy="85" r="2" fill="#dc2626"/><text x="58" y="100" font-size="7" fill="#1a73e8">Qs</text><text x="138" y="100" font-size="7" fill="#dc2626">Qd</text><text x="80" y="78" font-size="8" fill="#f59e0b">shortage</text></svg>', 11, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Why did Berlin''s Mietendeckel rent freeze (2020-21) fail?', 'Rents capped at 2019 levels caused the supply of rentals to fall about 60% as landlords withdrew or converted properties. Housing quality fell. Germany''s Constitutional Court struck the law down in 2021 — a textbook case of price-ceiling failure.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Give one UK example of a minimum price and its purpose.', 'Scotland''s 50p per unit minimum price for alcohol (2018) sets a floor above the equilibrium price for cheap, high-strength drinks to reduce alcohol-related harm. Also: National Living Wage as a floor in the labour market.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'Explain how tradable pollution permits (cap and trade) work.', 'Government caps total emissions and issues permits. Firms with cheap abatement sell surplus permits; those with expensive abatement buy them. The EU ETS price rose from ~5 euros (2017) to over 80 euros/tonne (2023), cutting covered emissions ~43% since 2005.', 14, 'alevel'),
  ('Economics', 'Edexcel A', '1.2', 'Market Failure & Government Intervention', 'What is government failure?', 'When intervention to correct market failure produces a worse allocation than no intervention. Causes include distorted price signals, unintended consequences (rent control shortages), information gaps, regulatory capture, and political short-termism.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Distinguish actual from potential economic growth.', 'Actual growth: rise in real GDP (movement towards/along PPF; AD shifts right). Potential growth: rise in productive capacity (PPF or LRAS shifts right). Sustainable growth needs both.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Distinguish nominal from real GDP and give the formula.', 'Nominal GDP is at current prices and rises with inflation alone. Real GDP is adjusted for inflation: Real GDP = (Nominal GDP / GDP Deflator) × 100. Real GDP is the meaningful measure of growth.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Give three limitations of GDP per capita as a welfare measure.', 'Hides income inequality; excludes informal/non-marketed work (housework, subsistence farming); ignores environmental damage; does not capture leisure or quality of life; needs PPP adjustment for international comparison.', 3, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'What does the HDI measure?', 'A composite index (0–1): life expectancy at birth, mean and expected years of schooling, and GNI per capita (PPP). Captures health and education alongside income — broader than GDP but ignores inequality and environment.', 4, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Distinguish CPI, CPIH and RPI.', 'CPI: ONS basket using geometric mean — UK 2% target, no mortgage interest. CPIH: CPI plus owner-occupier housing costs (ONS''s preferred measure). RPI: includes mortgage interest and council tax, uses arithmetic mean — tends higher; no longer a National Statistic.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Sketch demand-pull inflation on AD/AS.', 'AD shifts right along upward-sloping SRAS — both PL and real GDP rise; near full capacity, mostly PL rises. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="65" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="75" x2="100" y2="75" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="125" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="6" y="78" font-size="8" fill="#0B1E3F">PL1</text><text x="6" y="53" font-size="8" fill="#0B1E3F">PL2</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'What caused the UK''s 2022 cost-of-living crisis?', 'Mainly cost-push: Russia''s invasion of Ukraine spiked gas/oil prices, post-COVID supply disruption, and post-Brexit sterling weakness raised import costs. CPI peaked at 11.1% (Oct 2022) — a 41-year high. Bank Rate rose from 0.1% to 5.25%.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Why do central banks fear deflation?', 'Consumers postpone spending → AD falls further (deflationary spiral). Real value of debt rises → defaults. Real interest rates rise even at zero nominal rates (zero lower bound). Japan''s "lost decades" illustrate this.', 8, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Distinguish the Claimant Count from the LFS/ILO measure of unemployment.', 'Claimant Count: people claiming unemployment-related benefits (admin records, monthly, narrower). LFS/ILO: survey of ~40,000 households — without a job, sought work in last 4 weeks, can start within 2. LFS is internationally comparable.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'List four types of unemployment.', 'Frictional (between jobs), structural (mismatch of skills/location, e.g. UK deindustrialisation), cyclical/demand-deficient (recession), seasonal, real-wage/classical (wage above market-clearing).', 10, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'List the four components of the current account.', 'Trade in goods (visible: exports - imports), trade in services (invisibles: finance, tourism), primary income (investment income, wages), secondary income (transfers — aid, remittances).', 11, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Write the AD formula and the largest UK component.', 'AD = C + I + G + (X − M). Consumption (C) is the largest, around 60% of UK AD. Net exports (X − M) are typically negative for the UK.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Sketch AD/AS equilibrium with an outward AD shift.', 'AD shifts right along SRAS, raising real GDP and the price level. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,100 Q90,75 150,40" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="153" y="38" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="70" y1="25" x2="185" y2="105" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="100" font-size="8" fill="#dc2626">AD2</text><circle cx="86" cy="80" r="2" fill="#0B1E3F"/><circle cx="115" cy="60" r="2" fill="#0B1E3F"/><text x="100" y="130" font-size="9" fill="#0B1E3F">Y</text><text x="6" y="65" font-size="9" fill="#0B1E3F">PL</text></svg>', 13, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'Define MPC and MPS and state the relationship.', 'MPC = ΔC/ΔY (fraction of extra income spent). MPS = ΔS/ΔY (fraction saved). In a closed economy with no tax, MPC + MPS = 1. UK households'' MPC tends to be lower than developing-country MPC.', 14, 'alevel'),
  ('Economics', 'Edexcel A', '2.1', 'Economic Performance & AD', 'What is the accelerator effect?', 'A change in the rate of growth of consumer demand causes a magnified change in investment. Rising demand encourages firms to invest in new capacity; falling demand causes investment to collapse — amplifying the cycle.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Why is the SRAS curve upward-sloping?', 'In the short run, some costs are sticky (wages fixed by contracts). A higher PL raises profit margins, so firms expand output by hiring more labour and using capacity more intensively.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'List four causes of an SRAS leftward shift.', 'Higher wages, rising commodity/energy costs (e.g. 2022 gas spike), exchange rate depreciation (imported inputs costlier), higher indirect taxes (VAT), supply chain disruption.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Sketch SRAS shifting left and label the new equilibrium.', 'SRAS shifts left along AD: PL rises, real output falls — stagflation, e.g. UK 2022. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q155,20 170,15" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="172" y="17" font-size="8" fill="#1a73e8">SRAS1</text><path d="M35,90 Q80,60 115,30 Q135,15 145,10" fill="none" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="100" y="22" font-size="8" fill="#1a73e8">SRAS2</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><circle cx="115" cy="65" r="2" fill="#0B1E3F"/><circle cx="93" cy="50" r="2" fill="#0B1E3F"/></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Sketch the Classical (vertical) LRAS.', 'LRAS is vertical at full-employment output Yfe — long-run output is set by capacity, not PL. Shifts in AD only change PL. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="120" y1="20" x2="120" y2="115" stroke="#16a34a" stroke-width="2"/><text x="123" y="22" font-size="9" fill="#16a34a">LRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><text x="115" y="128" font-size="8" fill="#0B1E3F">Yfe</text></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Contrast Classical and Keynesian LRAS.', 'Classical: vertical at Yfe — economy self-corrects via flexible wages/prices. Keynesian: horizontal at low Y (spare capacity), upward-sloping middle, vertical at Yfe — wages/prices sticky downward, justifying demand-side intervention.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Sketch the Keynesian LRAS curve.', 'A backward L: horizontal at low output, then curves up, then vertical at Yfe. AD increases raise output without inflation when there is spare capacity. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,95 L100,95 Q130,90 140,60 L140,18" fill="none" stroke="#16a34a" stroke-width="2"/><text x="143" y="22" font-size="8" fill="#16a34a">LRAS</text><text x="135" y="128" font-size="8" fill="#0B1E3F">Yfe</text><text x="6" y="65" font-size="9" fill="#0B1E3F">PL</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'List four causes of a rightward LRAS shift.', 'Technological progress (AI, automation), more/better labour (immigration, training, education), higher capital investment, institutional improvements (deregulation, property rights), discovery of new resources.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'State the multiplier formula and what determines its size.', 'k = 1/(1 − MPC) = 1/MPW, where MPW = MPS + MPT + MPM. Larger MPC, lower taxes, low import propensity → larger multiplier. UK estimated multiplier is around 1.0–1.5 due to high leakages.', 8, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'If MPC = 0.8, calculate the multiplier and the impact of a £10bn injection.', 'k = 1/(1 − 0.8) = 1/0.2 = 5. A £10bn rise in G raises real GDP by £50bn in equilibrium, assuming spare capacity and no crowding out.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Sketch the short- and long-run Phillips curves.', 'SRPC slopes down (inflation–unemployment trade-off). LRPC is vertical at the NRU — no long-run trade-off. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,30 Q70,55 110,90 Q140,108 180,112" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="155" y="105" font-size="8" fill="#1a73e8">SRPC</text><line x1="115" y1="20" x2="115" y2="115" stroke="#dc2626" stroke-width="2"/><text x="118" y="22" font-size="8" fill="#dc2626">LRPC</text><text x="105" y="128" font-size="8" fill="#dc2626">NRU</text><text x="100" y="138" font-size="9" fill="#0B1E3F">U%</text><text x="4" y="65" font-size="9" fill="#0B1E3F">π%</text></svg>', 10, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Why is the Bank of England independent, and what is its mandate?', 'Granted operational independence in 1997 to remove political short-termism. The MPC (9 members) sets Bank Rate to meet the 2% CPI target. Beyond ±1%, the Governor must write an open letter to the Chancellor.', 11, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Outline the transmission mechanism of a Bank Rate cut.', 'Lower Bank Rate → cheaper borrowing, lower returns on saving → C and I rise; sterling depreciates → X − M rises; asset prices rise (wealth effect). All raise AD and inflation, with an 18–24 month lag.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Define quantitative easing (QE).', 'Unconventional monetary policy: the central bank creates electronic reserves to buy government bonds (gilts) and other assets. This raises bond prices, lowers long-term yields, and boosts liquidity, lending and AD. Used after 2008 and 2020.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Sketch expansionary fiscal policy on AD/AS.', 'Higher G or lower T shifts AD right; real GDP rises and PL increases. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="70" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/></svg>', 14, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Define crowding out.', 'When higher government borrowing pushes up interest rates, reducing private investment and consumption. More likely near full capacity; less of a concern in deep recessions with slack savings — relevant to the 2010–15 austerity debate.', 15, 'alevel'),
  ('Economics', 'Edexcel A', '2.2', 'AS, National Income & Macro Policy', 'Distinguish interventionist from market-based supply-side policies.', 'Interventionist: state action to fix market failures (state spending on training, infrastructure, R&D grants). Market-based: reducing state involvement (income/corporation tax cuts, deregulation, privatisation, weaker unions).', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Give three ways to measure the size of a firm.', 'Number of employees, turnover (revenue), market capitalisation, profit, market share. Rankings differ — a highly automated tech firm can be "large" by revenue but "small" by employees.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Why do small firms survive in markets dominated by large firms?', 'They serve niche markets, offer personalised service, supply larger firms, face barriers to growth (finance, management capacity), or owners satisfice. Some industries have a low minimum efficient scale (hairdressing, consultancy).', 2, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Distinguish horizontal, vertical and conglomerate integration with examples.', 'Horizontal: same stage, same industry (Facebook–Instagram, 2012). Vertical forward: closer to consumer (brewery buys pubs). Vertical backward: closer to inputs (supermarket buys a farm). Conglomerate: unrelated industries (Virgin Group).', 3, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Distinguish organic from external growth.', 'Organic: expansion from within using retained profits — slower, lower risk, preserves culture. External: M&A — fast access to markets/tech but cultural clashes; over half of mergers fail to add shareholder value.', 4, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Name four internal economies of scale.', 'Technical (specialised machinery, container principle), purchasing (bulk-buying — Tesco vs corner shop), managerial (specialist managers), financial (cheaper borrowing — Apple borrows at near-government rates), marketing, risk-bearing (Unilever''s 400+ brands).', 5, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Sketch the LRAC curve and label MES.', 'U-shape: economies of scale (falling), constant returns, then diseconomies (rising). MES is the lowest output where LRAC reaches its minimum. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,40 Q75,80 110,80 Q145,80 180,55" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="155" y="50" font-size="9" fill="#1a73e8">LRAC</text><line x1="110" y1="80" x2="110" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">MES</text><text x="40" y="105" font-size="7" fill="#16a34a">EoS</text><text x="140" y="40" font-size="7" fill="#dc2626">DoS</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Give three causes of diseconomies of scale.', 'Communication problems through many management layers, coordination difficulties, loss of control (shirking), worker alienation, bureaucracy, and the principal-agent problem.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Sketch the short-run cost curves (AFC, AVC, AC, MC).', 'AFC falls continuously; AVC and AC are U-shaped; MC cuts both AVC and AC at their minimums. The vertical gap between AC and AVC equals AFC. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q70,80 110,95 Q150,105 185,108" fill="none" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,2"/><text x="170" y="103" font-size="8" fill="#f59e0b">AFC</text><path d="M40,80 Q80,55 110,55 Q150,65 180,90" fill="none" stroke="#16a34a" stroke-width="1.5"/><text x="172" y="86" font-size="8" fill="#16a34a">AVC</text><path d="M40,55 Q80,35 115,40 Q150,50 180,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="172" y="71" font-size="8" fill="#1a73e8">AC</text><path d="M40,95 Q70,90 90,75 Q115,40 145,20" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="148" y="22" font-size="8" fill="#dc2626">MC</text></svg>', 8, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Why does MC always cut AC at AC''s minimum point?', 'When MC < AC, the next unit pulls the average down. When MC > AC, it pulls the average up. Therefore AC is at its minimum exactly where MC = AC — the same logic as exam-grade averages.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Why is MR twice as steep as AR for a price-maker?', 'To sell one more unit, the firm must lower the price on ALL units, not just the extra one. MR therefore falls faster than AR. For a linear demand curve, MR has the same intercept but bisects the horizontal distance.', 10, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Distinguish normal and supernormal profit.', 'Normal profit: minimum return needed to keep the firm in the industry (TR = TC, included as a cost). Supernormal profit: TR > TC — signals new firms to enter in contestable markets.', 11, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'State the profit-maximising rule.', 'Produce where MC = MR, with MC rising through MR. If MR > MC, the next unit adds to profit; if MR < MC, profit falls. Price is read up to the AR curve at that quantity.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'When should a loss-making firm shut down in the short run?', 'When AR < AVC. If P covers variable costs and contributes to fixed costs, the firm loses less by continuing. Shut down occurs at the minimum of AVC — the shutdown point.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Give three alternative business objectives to profit maximisation.', 'Revenue maximisation (MR = 0) — managers'' bonuses linked to sales. Sales maximisation (AC = AR, normal-profit constraint) — building share, e.g. Amazon. Satisficing — Simon: "good enough" profit. Survival, social/ethical objectives.', 14, 'alevel'),
  ('Economics', 'Edexcel A', '3.1', 'Business Growth & Objectives', 'Define the principal-agent problem.', 'Owners (principals) want profit max, but managers (agents) may pursue their own goals — perks, empire-building, easy life. Caused by information asymmetry. Mitigated through performance pay, share options and monitoring.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'List the four main market structures from most to least competitive.', 'Perfect competition, monopolistic competition, oligopoly, monopoly. They differ in number of firms, barriers to entry, product differentiation and price-setting power.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'State the assumptions of perfect competition.', 'Many small firms, homogeneous product, perfect information, no barriers to entry/exit, firms are price takers (so AR = MR = P), no externalities. A theoretical benchmark — closest real example is commodity markets.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Why does perfect competition deliver only normal profit in the long run?', 'No barriers mean any supernormal profit attracts new entrants. Market supply shifts right, price falls until P = minimum AC and supernormal profit is competed away. Both allocative (P=MC) and productive (min AC) efficiency are achieved.', 3, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Sketch the monopoly profit-max diagram with supernormal profit and DWL.', 'MC=MR sets Qm; price Pm read up to AR. Supernormal profit = (Pm − AC) × Qm. DWL triangle between Qm and the allocatively efficient Qc where MC=AR. <svg viewBox="0 0 200 150" width="180" height="135" style="display:block;margin:6px auto"><line x1="25" y1="125" x2="190" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="125" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="120" stroke="#16a34a" stroke-width="1.5"/><text x="183" y="123" font-size="8" fill="#16a34a">AR=D</text><line x1="35" y1="25" x2="107" y2="120" stroke="#f59e0b" stroke-width="1.5"/><text x="110" y="118" font-size="8" fill="#f59e0b">MR</text><path d="M35,100 Q70,90 100,75 Q130,55 165,30" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="167" y="32" font-size="8" fill="#dc2626">MC</text><path d="M35,80 Q80,55 110,52 Q150,60 175,80" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="178" y="84" font-size="8" fill="#1a73e8">AC</text><circle cx="80" cy="78" r="2" fill="#0B1E3F"/><line x1="80" y1="78" x2="80" y2="125" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="80" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="58" font-size="8" fill="#0B1E3F">Pm</text><text x="74" y="138" font-size="8" fill="#0B1E3F">Qm</text><rect x="35" y="55" width="45" height="13" fill="#16a34a" fill-opacity="0.2"/><polygon points="80,55 80,78 115,72" fill="#dc2626" fill-opacity="0.25"/></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Compared to perfect competition, what does a monopolist do?', 'Charges a higher price (Pm > Pc) and produces less (Qm < Qc). Allocatively inefficient (P > MC). Causes deadweight loss as consumer surplus is transferred to producer surplus or destroyed.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Define a natural monopoly.', 'A market where LRAC keeps falling at the level of total demand, so one firm can supply more cheaply than two. Examples: water, electricity transmission, rail. Usually regulated by Ofwat/Ofgem to prevent abuse.', 6, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Define oligopoly and its key feature.', 'A market dominated by a few large firms (e.g. UK supermarkets — Tesco, Sainsbury''s, Asda, Morrisons hold ~65%). Key feature is INTERDEPENDENCE — each firm''s decisions depend on rivals'' likely reactions.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Sketch the kinked demand curve (Sweezy model).', 'Above current price P*, demand is elastic (rivals don''t follow a price rise). Below, demand is inelastic (rivals match cuts). MR has a vertical discontinuity — explains price rigidity. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="40" y1="25" x2="105" y2="65" stroke="#16a34a" stroke-width="2"/><line x1="105" y1="65" x2="170" y2="110" stroke="#16a34a" stroke-width="2"/><text x="172" y="113" font-size="8" fill="#16a34a">D</text><circle cx="105" cy="65" r="2.5" fill="#0B1E3F"/><line x1="50" y1="40" x2="105" y2="80" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="105" x2="135" y2="115" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="80" x2="105" y2="105" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="2,2"/><text x="138" y="115" font-size="8" fill="#f59e0b">MR</text><line x1="25" y1="65" x2="105" y2="65" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="68" font-size="8" fill="#0B1E3F">P*</text></svg>', 8, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Distinguish overt from tacit collusion.', 'Overt: explicit price/output cartel agreement (e.g. OPEC) — illegal under UK/EU competition law. Tacit: parallel pricing or following a price leader, no formal agreement — harder to prosecute. CMA fined UK supermarkets for tacit dairy-price collusion in 2007.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Explain the prisoner''s dilemma in oligopoly.', 'Each firm''s dominant strategy is to undercut, even though both would gain from cooperating. Nash equilibrium is (Low, Low) — suboptimal. Repeated games and tit-for-tat strategies make tacit collusion sustainable in stable oligopolies.', 10, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Give one Schumpeterian argument FOR monopoly.', 'Supernormal profit funds R&D and "creative destruction." Without the prospect of monopoly profits — often via patents — firms have less incentive to innovate. E.g. pharmaceutical patents protect 20-year returns on drug development.', 11, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Define monopsony in the labour market and give an example.', 'A market with a single (or dominant) buyer of labour — the employer faces an upward-sloping supply of labour and exploits its power by hiring fewer workers at lower wages. UK NHS as the dominant buyer of doctors/nurses; large supermarket chains for farm produce.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'What is MRP and why is it the demand curve for labour?', 'Marginal Revenue Product = marginal physical product × marginal revenue. It''s the extra revenue from hiring one more worker. Firms hire up to where MRP = wage; downward-sloping MRP (diminishing returns) is the labour demand curve.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'How can the National Living Wage cause both higher wages and unemployment?', 'In a competitive labour market, a minimum wage above equilibrium creates excess supply of labour. In a monopsonistic market (e.g. UK NLW £11.44/hr from April 2024), it can raise BOTH wages and employment by countering employer power.', 14, 'alevel'),
  ('Economics', 'Edexcel A', '3.2', 'Market Structures & Labour', 'Give three causes of wage differentials.', 'Differences in skills/qualifications (human capital), compensating differentials (risky/unpleasant jobs), discrimination, trade union power, monopsony exploitation, geographic immobility, and differing demand (MRP) across sectors.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Define globalisation and give two causes.', 'The increasing integration and interdependence of economies through trade, investment, migration and technology. Causes: lower trade barriers (WTO — average tariffs from ~40% to ~3%), containerisation, ICT, capital deregulation, post-1978 China opening up.', 1, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Distinguish absolute and comparative advantage.', 'Absolute (Adam Smith): producing more output per unit of input than another country. Comparative (Ricardo): producing at lower opportunity cost. Mutually beneficial trade exists wherever opportunity costs differ — even if one country has absolute advantage in everything.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Sketch a comparative-advantage PPF table example.', 'France: 6 wine OR 3 cloth per worker (OC of 1 wine = 0.5 cloth). England: 2 wine OR 2 cloth (OC of 1 wine = 1 cloth). France has CA in wine; England in cloth. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="25" x2="115" y2="115" stroke="#1a73e8" stroke-width="2"/><text x="32" y="22" font-size="8" fill="#1a73e8">France</text><line x1="25" y1="85" x2="85" y2="115" stroke="#dc2626" stroke-width="2"/><text x="55" y="82" font-size="8" fill="#dc2626">England</text><text x="6" y="65" font-size="9" fill="#0B1E3F">Wine</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Cloth</text></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Give three limitations of the comparative advantage model.', 'Assumes constant opportunity costs (PPFs are linear), no transport costs, perfect factor mobility within countries, no externalities, only two goods/two countries, free trade. Static — ignores dynamic shifts (e.g. South Korea moving from textiles to semiconductors).', 4, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'State the formula for terms of trade.', 'Terms of Trade = (Index of Export Prices / Index of Import Prices) × 100. Improvement: export prices rise relative to imports — fewer exports needed to buy the same imports, but volumes may fall.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Sketch a tariff diagram and label the key areas.', 'World price Pw rises to Pw+t. Domestic supply rises Q1→Q2; demand falls Q4→Q3; imports = Q3−Q2. Government revenue = t × (Q3−Q2); two DWL triangles for production and consumption inefficiency. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="110" x2="170" y2="20" stroke="#1a73e8" stroke-width="1.8"/><text x="172" y="22" font-size="8" fill="#1a73e8">Sd</text><line x1="35" y1="25" x2="170" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="172" y="113" font-size="8" fill="#dc2626">D</text><line x1="25" y1="95" x2="180" y2="95" stroke="#16a34a" stroke-width="1.5"/><text x="160" y="92" font-size="7" fill="#16a34a">Pw</text><line x1="25" y1="80" x2="180" y2="80" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="3,2"/><text x="155" y="77" font-size="7" fill="#f59e0b">Pw+t</text><line x1="50" y1="95" x2="50" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="70" y1="80" x2="70" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="135" y1="80" x2="135" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="155" y1="95" x2="155" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><rect x="70" y="80" width="65" height="15" fill="#f59e0b" fill-opacity="0.25"/><text x="83" y="91" font-size="7" fill="#b45309">Govt rev</text><polygon points="50,95 70,95 70,80" fill="#dc2626" fill-opacity="0.3"/><polygon points="135,95 155,95 135,80" fill="#dc2626" fill-opacity="0.3"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Distinguish a tariff from a quota.', 'Tariff: tax on imports — raises domestic price, generates government revenue. Quota: physical limit on import quantity — also raises price but gives the rent to whoever holds the import licences (no revenue). Both create DWL.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Give three arguments for protectionism.', 'Infant-industry argument (until economies of scale achieved), strategic industries (defence, food security), anti-dumping (counter foreign sales below cost), preventing structural unemployment, raising government revenue, and maintaining environmental/labour standards.', 8, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Distinguish a customs union from a free-trade area.', 'Free-trade area: members eliminate internal tariffs but set their own external tariffs (e.g. NAFTA/USMCA). Customs union: also has a Common External Tariff with non-members (e.g. EU). Single Market goes further — free movement of goods, services, capital, labour.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'What was the EU Common Agricultural Policy and one criticism?', 'The CAP supported EU farmers via minimum prices and subsidies — historically created huge surpluses ("butter mountains", "wine lakes"), distorted world prices and harmed developing-country exporters. Reformed since 2003 toward direct payments tied to environmental criteria.', 10, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Sketch an exchange rate appreciation.', 'Demand for sterling rises (e.g. higher UK rates attract hot money). Equilibrium £ price rises. Effect: exports dearer abroad, imports cheaper. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">D£1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">D£2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S£</text><circle cx="92" cy="72" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="57" r="2.5" fill="#0B1E3F"/><text x="6" y="55" font-size="8" fill="#0B1E3F">$/£</text><text x="100" y="130" font-size="8" fill="#0B1E3F">Q£</text></svg>', 11, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'State the Marshall-Lerner condition.', 'A currency depreciation improves the current account if the sum of price elasticities of demand for exports and imports exceeds one (|PEDx| + |PEDm| > 1). If elasticities are too low (J-curve effect), the deficit may worsen first.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Distinguish current-account-deficit causes that are sustainable from those that are not.', 'Sustainable: financed by long-term FDI inflows, reflecting attractiveness (UK 3–5% of GDP). Unsustainable: financed by short-term hot-money inflows or rising external debt; rising relative inflation; structural deindustrialisation.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'List three policies to correct a current account deficit.', 'Expenditure-switching (depreciation, tariffs/quotas), expenditure-reducing (contractionary fiscal/monetary policy), and supply-side policies to raise productivity and non-price competitiveness (training, R&D incentives).', 14, 'alevel'),
  ('Economics', 'Edexcel A', '4.1', 'International Economics & Trade', 'Distinguish FDI from portfolio investment.', 'FDI: long-term investment giving control (over 10% ownership) — building factories, acquisitions (e.g. Nissan in Sunderland). Portfolio: shorter-term financial investment (shares, bonds) without operational control. FDI is generally more stable and brings management/technology.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Distinguish economic growth from economic development.', 'Growth: quantitative — increase in real GDP. Development: qualitative — improvements in living standards, health, education, freedoms and sustainability. Growth is necessary but not sufficient for development (e.g. resource-rich states with high GDP and poor HDI).', 1, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'List three indicators of development beyond GDP per capita.', 'HDI (life expectancy + schooling + GNI per capita PPP), MPI (10 indicators of health/education/living standards), Gini coefficient, infant mortality rate, literacy rate, gender inequality index.', 2, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Distinguish absolute from relative poverty.', 'Absolute: income too low to meet basic needs — World Bank line is $2.15/day (2022 PPP). Relative: below 60% of median household income (UK definition). A person can be relatively poor without being absolutely poor.', 3, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Sketch a Lorenz curve and explain the Gini coefficient.', 'Cumulative % income (y) vs cumulative % population (x). Diagonal = perfect equality; Lorenz sags below it. Gini = Area A / (Area A + Area B), 0 (equal) to 1 (one person has all). UK ~0.35; Scandinavia ~0.27; South Africa ~0.63. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="180" y2="20" stroke="#64748b" stroke-width="1" stroke-dasharray="3,3"/><text x="120" y="55" font-size="7" fill="#64748b">equality</text><path d="M25,115 Q90,108 130,80 Q160,55 180,20" fill="none" stroke="#dc2626" stroke-width="2"/><text x="100" y="100" font-size="8" fill="#dc2626">Lorenz</text><text x="60" y="80" font-size="8" fill="#0B1E3F">A</text><text x="130" y="55" font-size="8" fill="#0B1E3F">B</text><text x="40" y="130" font-size="8" fill="#0B1E3F">% pop</text><text x="6" y="65" font-size="8" fill="#0B1E3F">%Y</text></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Give three problems caused by primary product dependency.', 'Price volatility (commodity swings of 50%+), Prebisch-Singer (declining terms of trade for primaries vs manufactures), Dutch Disease (resource boom appreciates currency, hurts other exporters), resource curse (corruption, conflict — Nigeria, DRC), low value-added.', 5, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'State the Harrod-Domar model and one limitation.', 'Growth rate g = s/k (savings ratio over capital-output ratio). To grow faster, raise savings or productivity of capital. Limitation: assumes a fixed k, ignores diminishing returns, and ignores institutions, governance and human capital. Justifies aid to fill the savings gap.', 6, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Outline the Lewis structural-change model.', 'Surplus labour (MP near zero) shifts from low-productivity agriculture to higher-productivity industry. Modern-sector profits are reinvested, absorbing more labour until the Lewis turning point — when wages rise across the economy. China reached this around 2010-15.', 7, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Give one criticism of Rostow''s stages of growth.', 'Eurocentric — assumes all countries follow the linear Western path; ignores colonialism, dependency theory and structural disadvantages; assumes investment alone drives growth, ignoring institutions, geography and environmental limits.', 8, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'List three causes of inequality within countries.', 'Unequal access to education and healthcare, differences in inheritance and wealth, labour market discrimination, regressive tax/benefit systems, technological change favouring skilled workers, declining union power, globalisation pressure on unskilled wages.', 9, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Sketch the Kuznets curve.', 'Inverted-U: inequality rises in early industrialisation as workers shift to higher-paid modern sector, peaks, then falls as education spreads, the welfare state develops and demand for skilled labour rises. Empirically contested. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,100 Q70,30 105,30 Q150,30 180,100" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="80" y="40" font-size="8" fill="#1a73e8">Kuznets</text><text x="6" y="65" font-size="8" fill="#0B1E3F">Gini</text><text x="80" y="130" font-size="8" fill="#0B1E3F">GDP/capita</text></svg>', 10, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Outline the role of microfinance in development.', 'Small loans (and savings/insurance) for poor entrepreneurs without collateral — pioneered by Grameen Bank in Bangladesh (Yunus, Nobel 2006). Empowers women, supports informal businesses. Critics: high interest rates, debt traps, mixed RCT evidence on poverty reduction.', 11, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Distinguish tied from untied aid.', 'Tied aid: must be spent on goods/services from the donor country — boosts donor industries but may be poor value. Untied aid: recipient chooses suppliers — generally more effective. Bilateral: country-to-country; multilateral: through bodies like the World Bank or UN.', 12, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Give one argument for and one against trade liberalisation as a development strategy.', 'For: access to larger markets, FDI, technology transfer (South Korea, Vietnam). Against: vulnerable infant industries, primary-product dependency reinforced, jobs lost to cheaper imports, current-account deterioration. Outcomes depend on institutions and policy support.', 13, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'List three roles of NGOs and the World Bank/IMF in development.', 'World Bank: long-term development loans for infrastructure and human capital. IMF: short-term BoP support, conditionality (often austerity-linked, criticised as "Washington Consensus"). NGOs (Oxfam, BRAC): grassroots delivery, advocacy, emergency relief.', 14, 'alevel'),
  ('Economics', 'Edexcel A', '4.2', 'Poverty, Inequality & Development', 'Give two strategies to reduce absolute poverty.', 'Investing in education and healthcare (raises human capital and earning power), conditional cash transfers (Brazil''s Bolsa Família), microfinance, infrastructure, debt relief (HIPC initiative), trade access for developing-country exports, and pro-poor growth strategies.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Define opportunity cost and give a UK government example.', 'The value of the next best alternative foregone when a choice is made. E.g. the £100bn+ committed to HS2 has an opportunity cost equal to the next best use of the funds, such as new hospitals, schools or renewable energy.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Sketch a PPF and label efficient, inefficient and unattainable points.', 'Concave (bowed-out) curve. Points ON the curve are productively efficient; INSIDE are inefficient (spare capacity, e.g. UK 2020 furlough); OUTSIDE are currently unattainable. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,25 Q175,25 180,115" fill="none" stroke="#1a73e8" stroke-width="2"/><circle cx="80" cy="55" r="3" fill="#16a34a"/><text x="86" y="52" font-size="8" fill="#16a34a">A</text><circle cx="80" cy="100" r="3" fill="#f59e0b"/><text x="86" y="103" font-size="8" fill="#f59e0b">B</text><circle cx="160" cy="50" r="3" fill="#dc2626"/><text x="166" y="48" font-size="8" fill="#dc2626">C</text><text x="80" y="132" font-size="9" fill="#0B1E3F">Consumer goods</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Capital</text></svg>', 2, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Why is the PPF concave (bowed outwards)?', 'Because of the law of increasing opportunity cost: factors of production are not perfectly adaptable between uses, so producing more of one good means giving up increasingly more of the other.', 3, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Name the four factors of production and their factor rewards.', 'Land — rent (oil, farmland). Labour — wages. Capital — interest (machinery, factories). Enterprise — profit (e.g. James Dyson, Elon Musk). Capital includes physical and human capital.', 4, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Sketch supply and demand and show the effect of a rightward shift in demand.', 'Non-price factor (e.g. rising income) shifts D right. New equilibrium at higher P and higher Q — illustrated by UK EV demand rising from ~1,900 (2013) to over 300,000 (2023). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="2"/><text x="163" y="113" font-size="9" fill="#dc2626">D1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="172" y="98" font-size="9" fill="#dc2626">D2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><circle cx="92" cy="72" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="57" r="2.5" fill="#0B1E3F"/><line x1="92" y1="72" x2="118" y2="57" stroke="#64748b" stroke-width="0.8"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 5, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'State the three functions of the price mechanism.', 'Signalling (prices convey information about scarcity), incentive (high prices encourage supply and discourage demand) and rationing (allocating scarce goods to those willing and able to pay). Adam Smith called this the "invisible hand".', 6, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Sketch market equilibrium with consumer and producer surplus shaded.', 'CS is the triangle below D and above Pe; PS is above S and below Pe. CS+PS = total welfare, maximised at free-market equilibrium (allocative efficiency). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><polygon points="35,25 107,67 25,67" fill="#16a34a" fill-opacity="0.18"/><text x="50" y="55" font-size="7" fill="#16a34a">CS</text><polygon points="35,110 107,67 25,67" fill="#1a73e8" fill-opacity="0.18"/><text x="50" y="92" font-size="7" fill="#1a73e8">PS</text><circle cx="107" cy="67" r="2.5" fill="#0B1E3F"/><line x1="25" y1="67" x2="107" y2="67" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="107" y1="67" x2="107" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="70" font-size="9" fill="#0B1E3F">Pe</text><text x="103" y="128" font-size="9" fill="#0B1E3F">Qe</text></svg>', 7, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'State the formula for PED and explain its sign.', 'PED = % change in quantity demanded ÷ % change in price. Almost always negative due to the law of demand; we usually compare absolute values. |PED| > 1 = elastic, < 1 = inelastic.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Sketch and contrast price-elastic and price-inelastic demand.', 'Elastic: relatively flat (|PED| > 1, e.g. branded clothing, Coke vs Pepsi). Inelastic: relatively steep (|PED| < 1, e.g. petrol, insulin, addictive goods). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="50" x2="180" y2="80" stroke="#16a34a" stroke-width="2"/><text x="155" y="45" font-size="8" fill="#16a34a">elastic</text><line x1="95" y1="20" x2="125" y2="115" stroke="#dc2626" stroke-width="2"/><text x="128" y="40" font-size="8" fill="#dc2626">inelastic</text><text x="10" y="65" font-size="9" fill="#0B1E3F">P</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 9, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'If demand is price-inelastic, how should a firm change price to raise revenue?', 'Raise price. With |PED| < 1, the proportional fall in Q is smaller than the rise in P, so total revenue (P × Q) increases. This is why luxury brands rarely discount and why HMRC taxes petrol/cigarettes heavily.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Distinguish normal, inferior and luxury goods using YED.', 'YED = %ΔQd ÷ %ΔY. Normal: YED > 0. Luxury: YED > 1 (e.g. holidays, organic food). Necessity: 0 < YED < 1 (toothpaste). Inferior: YED < 0 (e.g. Aldi/Lidl grew rapidly during 2008-09 as incomes fell).', 11, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'What does cross elasticity of demand (XED) tell a business?', 'How demand for good A responds to a price change of good B. Positive XED = substitutes (Coke & Pepsi). Negative XED = complements (printers & ink, cars & petrol). Used for pricing strategy and bundling decisions.', 12, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Why is UK housing supply highly price-inelastic?', 'Strict planning rules, scarce land in the South East, skilled-labour shortages and long build times. House prices rose ~60% from 2013-2023 but completions only rose from ~120,000 to ~180,000/year — demand increases mostly feed into higher prices, not more houses.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'List four determinants of PED.', 'Availability of substitutes (most important), necessity vs luxury, proportion of income spent, time period (more elastic in the long run), brand loyalty/addictiveness, and how narrowly the market is defined.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '1.1', 'How Markets Work & Surplus', 'Why is COVID-19 a textbook PPF example for the UK?', 'In 2020 UK GDP fell 9.7% — the largest annual fall in over 300 years. Furlough kept millions of workers idle, moving the economy from near its PPF to well INSIDE it. Long COVID and early retirements may also have shifted the PPF inward by reducing labour supply.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Define market failure and state the social-optimum condition.', 'When the free market misallocates resources so social welfare is not maximised. The socially optimal output is where MSC = MSB, with MSC = MPC + MEC and MSB = MPB + MEB. Externalities cause divergence between private and social costs/benefits.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Sketch a negative production externality with welfare loss.', 'MSC sits above MPC (the supply curve). Free market produces at Qm where MPC=D; social optimum is Q* where MSC=D. The triangle between Q* and Qm is the welfare (deadweight) loss from over-production. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="32" font-size="8" fill="#1a73e8">MPC</text><line x1="35" y1="80" x2="180" y2="20" stroke="#dc2626" stroke-width="1.8"/><text x="158" y="18" font-size="8" fill="#dc2626">MSC</text><line x1="35" y1="30" x2="180" y2="100" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="105" font-size="8" fill="#16a34a">D=MSB</text><circle cx="115" cy="68" r="2" fill="#1a73e8"/><circle cx="100" cy="60" r="2" fill="#dc2626"/><line x1="115" y1="68" x2="115" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="60" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="110" y="128" font-size="8" fill="#1a73e8">Qm</text><text x="92" y="128" font-size="8" fill="#dc2626">Q*</text><polygon points="100,60 115,68 115,52" fill="#dc2626" fill-opacity="0.25"/></svg>', 2, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Give a UK example of a negative production externality.', 'UK manufacturing/energy air pollution: Public Health England estimates 28,000-36,000 premature deaths/year. Market price ignores NHS, mortality and environmental costs — addressed via the UK ETS (carbon permits) and Climate Change Levy.', 3, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Sketch a positive consumption externality (e.g. vaccination).', 'MSB lies above MPB. Market output Qm is below the social optimum Q*; the good is under-consumed. UK COVID-19 vaccines made free at point of use to internalise the herd-immunity benefit. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="30" stroke="#dc2626" stroke-width="1.8"/><text x="155" y="28" font-size="8" fill="#dc2626">S=MSC</text><line x1="35" y1="35" x2="180" y2="105" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="110" font-size="8" fill="#1a73e8">MPB</text><line x1="35" y1="20" x2="180" y2="90" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="95" font-size="8" fill="#16a34a">MSB</text><circle cx="100" cy="65" r="2" fill="#1a73e8"/><circle cx="120" cy="68" r="2" fill="#16a34a"/><line x1="100" y1="65" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="120" y1="68" x2="120" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="92" y="128" font-size="8" fill="#1a73e8">Qm</text><text x="115" y="128" font-size="8" fill="#16a34a">Q*</text><polygon points="100,65 120,68 100,52" fill="#16a34a" fill-opacity="0.25"/></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'State the two characteristics of a public good and the resulting failure.', 'Non-excludable (cannot prevent non-payers using it) and non-rival (one person''s use does not reduce availability for others). Together they cause the free-rider problem: rational agents won''t pay, so the market provides nothing — a "missing market".', 5, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Distinguish a public good from a quasi-public good.', 'Pure public goods (defence, street lighting) are fully non-excludable AND non-rival. Quasi-public goods are partially excludable or rival — roads (excludable via tolls; rivalrous in congestion), parks (entry fees possible), BBC (could be encrypted).', 6, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Distinguish a merit good from a positive externality.', 'A merit good is under-consumed for TWO reasons: (1) information failure — consumers underestimate private benefit (e.g. teenager underrating education), AND (2) positive externalities (e.g. educated workers benefit employers). NHS and state schooling are textbook merit goods.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Distinguish adverse selection from moral hazard.', 'Adverse selection: hidden info BEFORE a transaction (Akerlof''s used-car "lemons"; unhealthy people more likely to buy insurance). Moral hazard: changed behaviour AFTER (insured drivers take more risks; "too big to fail" banks).', 8, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Sketch the incidence of an indirect (specific) tax.', 'Tax shifts S up by the tax amount (parallel shift). Price rises P0→P1, quantity falls Q0→Q1. Vertical gap between S and S+tax is the per-unit tax. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="105" x2="180" y2="40" stroke="#1a73e8" stroke-width="1.8"/><text x="160" y="38" font-size="8" fill="#1a73e8">S</text><line x1="35" y1="85" x2="180" y2="20" stroke="#1a73e8" stroke-width="1.8" stroke-dasharray="4,3"/><text x="155" y="18" font-size="8" fill="#1a73e8">S+tax</text><circle cx="110" cy="68" r="2" fill="#0B1E3F"/><circle cx="100" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="68" x2="110" y2="68" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="100" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="10" y="71" font-size="8" fill="#0B1E3F">P0</text><text x="10" y="53" font-size="8" fill="#0B1E3F">P1</text></svg>', 9, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'How did the UK Soft Drinks Industry Levy (2018) work, and was it effective?', 'Drinks with 5-8g sugar/100ml taxed at 18p/litre; over 8g at 24p/litre. Sugary-drink purchases fell ~30% and producers (Lucozade, Ribena, Fanta) reformulated below the threshold — most of the impact came on the supply side rather than as a pure demand response.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Sketch a maximum price (price ceiling) and label the shortage.', 'Pmax sits below Pe, creating excess demand (Qd > Qs). Used for rent controls; can lead to black markets, queues and reduced quality. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S</text><line x1="25" y1="85" x2="180" y2="85" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,3"/><text x="160" y="82" font-size="8" fill="#f59e0b">Pmax</text><circle cx="65" cy="85" r="2" fill="#1a73e8"/><circle cx="143" cy="85" r="2" fill="#dc2626"/><text x="58" y="100" font-size="7" fill="#1a73e8">Qs</text><text x="138" y="100" font-size="7" fill="#dc2626">Qd</text><text x="80" y="78" font-size="8" fill="#f59e0b">shortage</text></svg>', 11, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Sketch a minimum price (price floor) and give a UK example.', 'Pmin set above Pe creates excess supply. Examples: National Living Wage (£11.44/hr in 2024); Scotland''s 50p/unit minimum alcohol price (2018) to reduce alcohol-related harm. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="8" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S</text><line x1="25" y1="50" x2="180" y2="50" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,3"/><text x="160" y="47" font-size="8" fill="#f59e0b">Pmin</text><circle cx="62" cy="50" r="2" fill="#dc2626"/><circle cx="143" cy="50" r="2" fill="#1a73e8"/><text x="58" y="42" font-size="7" fill="#dc2626">Qd</text><text x="138" y="42" font-size="7" fill="#1a73e8">Qs</text><text x="80" y="65" font-size="8" fill="#f59e0b">surplus</text></svg>', 12, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'Explain how tradable pollution permits (cap and trade) work.', 'Government caps total emissions and issues permits. Firms with cheap abatement sell surplus permits; those with expensive abatement buy them. The EU ETS price rose from ~5 euros (2017) to over 80 euros/tonne (2023), cutting covered emissions ~43% since 2005.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'How did the Wonga payday lending case illustrate information failure?', 'Wonga charged APRs over 4,000% but consumers focused on the headline cash sum, not the true cost — a textbook info-failure case. The FCA capped total cost at 100% of the principal in 2015 and forced clearer disclosure; over-consumption fell.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '1.2', 'Market Failure & Government Intervention', 'What is government failure? Give a classic example.', 'When intervention produces a worse allocation than no intervention. The EU CAP set minimum farm prices, creating "butter mountains" and "wine lakes" that were dumped on world markets, harming developing-country farmers — billions wasted by distorting price signals.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'State the three methods of measuring GDP.', 'Output (sum of value added across sectors), Income (wages + rent + interest + profits) and Expenditure (C + I + G + (X − M)). All three should give the same figure — the national income identity.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Distinguish nominal from real GDP and state why real matters.', 'Nominal GDP is at current prices and rises with inflation alone. Real GDP is adjusted for inflation using the GDP deflator. Real GDP is the meaningful measure of growth — it shows the actual change in output volume.', 2, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Give four limitations of GDP per capita as a welfare measure.', 'Hides income inequality; excludes the informal/shadow economy and unpaid work; ignores environmental damage and "bads" (oil-spill clean-ups raise GDP); ignores leisure, health and freedoms; needs PPP adjustment for cross-country comparison.', 3, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'What does the HDI measure and what are its weaknesses?', 'A 0-1 composite of life expectancy, mean and expected years of schooling, and GNI per capita (PPP). Strength: broader than GDP. Weakness: ignores inequality (use IHDI), environment, gender, freedoms; only three dimensions.', 4, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Distinguish CPI from RPI.', 'CPI: ONS basket using geometric mean — UK 2% target measure used by the BoE, no mortgage interest. RPI: includes mortgage interest payments and council tax, uses arithmetic mean — tends higher; no longer a National Statistic but still used for index-linked gilts and rail fares.', 5, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Sketch demand-pull inflation on AD/AS.', 'AD shifts right along upward-sloping SRAS — both PL and real GDP rise; near full capacity, mostly PL rises. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="65" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/><line x1="25" y1="75" x2="100" y2="75" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="50" x2="125" y2="50" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="6" y="78" font-size="8" fill="#0B1E3F">PL1</text><text x="6" y="53" font-size="8" fill="#0B1E3F">PL2</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'What were the main drivers of UK CPI peaking at 11.1% in October 2022?', 'Mainly cost-push: Russia''s invasion of Ukraine spiked wholesale gas prices over 400%; post-COVID supply-chain disruption; weaker pound raising import costs. Real wages fell sharply. Bank Rate rose from 0.1% to 5.25% — the sharpest fall in living standards on record.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Why do central banks fear deflation?', 'Consumers postpone spending → AD falls further (deflationary spiral). Real value of debt rises → defaults. Real interest rates rise even at zero nominal rates (zero lower bound). Japan''s "lost decades" illustrate the trap.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Distinguish the Claimant Count from the LFS/ILO measure of unemployment.', 'Claimant Count: people claiming JSA/UC searching for work — monthly, narrow, sensitive to benefit rules. LFS/ILO: quarterly survey of ~40,000 households (without a job, sought work in last 4 weeks, can start within 2). LFS is internationally comparable.', 9, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Why has UK structural unemployment persisted in former mining/steel areas?', '1980s decline of coal, steel and shipbuilding left South Wales, the North and Central Scotland with skills not transferable to South-East services. Hysteresis (skill atrophy) and geographical immobility have kept unemployment and incomes below the national average decades later.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'List the three accounts of the balance of payments.', 'Current account (trade in goods and services, primary income, secondary income), capital account (small — debt forgiveness, sale of patents) and financial account (FDI, portfolio investment, reserves). Overall the BoP balances to zero.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Why does the UK run a persistent current account deficit?', 'High consumer MPM (strong demand for imported cars, electronics, energy); deindustrialisation since the 1980s reducing goods exports; historically strong pound; low savings rate; and a primary-income deficit as foreign owners of UK assets repatriate income.', 12, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'List the four phases of the economic cycle.', 'Boom (high growth, low U, rising inflation, +ve output gap), slowdown (growth decelerates), recession (two consecutive quarters of negative GDP growth, rising U, -ve output gap) and recovery (GDP grows again, U falls).', 13, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Define the output gap and explain its sign.', 'Difference between actual and potential GDP. Positive gap: actual > potential — overheating, inflationary pressure. Negative gap: actual < potential — spare capacity, higher unemployment, deflationary pressure (e.g. UK 2009-13).', 14, 'alevel'),
  ('Economics', 'Edexcel B', '2.1', 'National Economic Performance', 'Sketch the SRPC and LRPC.', 'SRPC slopes down (inflation–unemployment trade-off; Phillips 1958). LRPC is vertical at the NRU (Friedman/Phelps) — no long-run trade-off. Stagflation in the 1970s broke the simple SRPC and supported the expectations view. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,30 Q70,55 110,90 Q140,108 180,112" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="155" y="105" font-size="8" fill="#1a73e8">SRPC</text><line x1="115" y1="20" x2="115" y2="115" stroke="#dc2626" stroke-width="2"/><text x="118" y="22" font-size="8" fill="#dc2626">LRPC</text><text x="105" y="128" font-size="8" fill="#dc2626">NRU</text><text x="100" y="138" font-size="9" fill="#0B1E3F">U%</text><text x="4" y="65" font-size="9" fill="#0B1E3F">π%</text></svg>', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Write the AD formula and the rough UK shares.', 'AD = C + I + G + (X − M). UK shares (approx): C ≈ 60%, I ≈ 17%, G ≈ 20%, (X − M) ≈ −2%. C is the largest component; net exports are usually negative.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Why is the AD curve downward sloping?', 'Wealth/real-balance effect (lower PL raises real wealth → C up); interest-rate effect (lower PL → lower money demand → lower r → I and C up); trade effect (lower PL → exports cheaper, imports dearer → X−M up).', 2, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Sketch SRAS shifting left and label the new equilibrium.', 'SRAS shifts left along AD: PL rises, real output falls — stagflation, e.g. UK 2022 energy shock. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q155,20 170,15" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="172" y="17" font-size="8" fill="#1a73e8">SRAS1</text><path d="M35,90 Q80,60 115,30 Q135,15 145,10" fill="none" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="100" y="22" font-size="8" fill="#1a73e8">SRAS2</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><circle cx="115" cy="65" r="2" fill="#0B1E3F"/><circle cx="93" cy="50" r="2" fill="#0B1E3F"/></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Sketch the Classical (vertical) LRAS.', 'LRAS is vertical at full-employment output Yfe — long-run output is set by capacity, not PL. AD shifts only change PL. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="120" y1="20" x2="120" y2="115" stroke="#16a34a" stroke-width="2"/><text x="123" y="22" font-size="9" fill="#16a34a">LRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD</text><text x="115" y="128" font-size="8" fill="#0B1E3F">Yfe</text></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Sketch the Keynesian LRAS curve.', 'Backward-L: horizontal at low Y (spare capacity), curves up, vertical at Yfe. AD increases raise output without inflation when there is spare capacity — justifying fiscal expansion in recession. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,95 L100,95 Q130,90 140,60 L140,18" fill="none" stroke="#16a34a" stroke-width="2"/><text x="143" y="22" font-size="8" fill="#16a34a">LRAS</text><text x="135" y="128" font-size="8" fill="#0B1E3F">Yfe</text><text x="6" y="65" font-size="9" fill="#0B1E3F">PL</text></svg>', 5, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'List four causes of a rightward LRAS shift.', 'Better technology (AI, automation), more/better labour (immigration, training, education), higher capital investment (HS2, broadband), institutional reform (deregulation, secure property rights), discovery of new resources.', 6, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'State the multiplier formula and the size of the UK multiplier.', 'k = 1/(1 − MPC) = 1/MPW where MPW = MPS + MPT + MPM. Larger MPC, lower taxes, low import propensity → larger k. UK multiplier estimated 1.0-1.5 — leakages to imports and tax keep it modest.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'If MPC = 0.8, calculate the multiplier and the impact of a £10bn injection.', 'k = 1/(1 − 0.8) = 5. A £10bn rise in G raises real GDP by £50bn in equilibrium, assuming spare capacity and no crowding out.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Why is the Bank of England independent, and what is its mandate?', 'Granted operational independence in 1997 to remove political short-termism. The MPC (9 members) sets Bank Rate to meet the 2% CPI target. If inflation deviates by more than ±1pp, the Governor must write an open letter to the Chancellor.', 9, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Outline the transmission mechanism of a Bank Rate cut.', 'Lower Bank Rate → cheaper borrowing, lower returns on saving → C and I rise; sterling depreciates → X − M rises; asset prices rise (wealth effect). All raise AD and inflation, with an 18-24 month lag.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'What is QE and how big was the UK programme?', 'Unconventional monetary policy: the BoE creates electronic reserves to buy gilts and other assets, raising bond prices, lowering long yields and boosting lending and AD. UK programme reached £895bn before quantitative tightening (QT) began in 2022.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Sketch expansionary fiscal policy on AD/AS.', 'Higher G or lower T shifts AD right; real GDP rises and PL increases — biggest output effect when spare capacity exists. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,105 Q90,80 130,45 Q150,25 165,18" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="167" y="20" font-size="8" fill="#1a73e8">SRAS</text><line x1="40" y1="30" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">AD1</text><line x1="70" y1="25" x2="185" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">AD2</text><circle cx="100" cy="75" r="2" fill="#0B1E3F"/><circle cx="125" cy="50" r="2" fill="#0B1E3F"/></svg>', 12, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Distinguish a cyclical from a structural deficit.', 'Cyclical deficit: caused by the economic cycle (lower tax receipts, higher benefits in recession) — disappears at full employment. Structural deficit: persists even at full employment — reflects a fundamental mismatch between spending commitments and tax revenue.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Compare UK 2010-15 austerity with the COVID fiscal response.', 'Austerity: contractionary — VAT rose to 20%, public-sector pay frozen, welfare cuts; deficit fell but recovery was sluggish. COVID: expansionary — £70bn furlough, business grants; deficit reached 15% of GDP (highest since WWII), debt over 100% of GDP, but mass unemployment was avoided.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Distinguish interventionist from market-based supply-side policies.', 'Interventionist: state action — education and training (T-Levels), R&D tax credits, infrastructure (HS2, broadband), industrial strategy. Market-based: deregulation, privatisation (BT, British Gas), income/corporation tax cuts, weaker unions, welfare reform (Universal Credit).', 15, 'alevel'),
  ('Economics', 'Edexcel B', '2.2', 'Macroeconomic Policy', 'Why was the September 2022 mini-budget a textbook policy-conflict case?', 'Truss/Kwarteng announced large unfunded tax cuts — expansionary fiscal policy — at the same time the BoE was tightening monetary policy to fight 11.1% inflation. Markets feared unsustainable debt; gilt yields spiked, the pound fell, and the BoE had to intervene; the package was reversed and Truss resigned.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Give three reasons firms grow.', 'Economies of scale (lower AC → competitiveness/profit); market power (pricing and supplier bargaining power); risk diversification across products/markets; managerial motives (Marris — pay, prestige); shareholder pressure for returns; survival in competitive markets.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Distinguish horizontal, vertical and conglomerate integration with examples.', 'Horizontal: same stage, same industry (Facebook–Instagram). Vertical forward: closer to consumer (a brewery buying a pub chain). Vertical backward: closer to inputs (a carmaker buying a steel supplier). Conglomerate: unrelated industries (Virgin Group — airlines, telecoms, banking).', 2, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Distinguish organic from external growth — and why might external growth fail?', 'Organic: from within — retained profits, less risky, preserves culture, but slow. External: M&A — fast access to markets/tech but cultural clashes; McKinsey/KPMG find 50-70% of mergers destroy shareholder value (winner''s curse, integration failures, empire-building).', 3, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Name four internal economies of scale with firm-level examples.', 'Technical (cube-square rule for oil tankers); purchasing/bulk-buying (Tesco vs corner shop); managerial (specialist tax/HR/marketing teams in MNCs); financial (FTSE 100 firms borrow cheaper than SMEs); marketing (Coca-Cola TV ads costing fractions of a penny per bottle); risk-bearing (Unilever — 400+ brands across 190 countries).', 4, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Sketch the LRAC curve and label MES.', 'U-shape: economies of scale (falling AC), constant returns, then diseconomies (rising). MES is the lowest output where LRAC is minimised. High MES → fewer larger firms (oligopoly tendency in supermarkets, banking). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,40 Q75,80 110,80 Q145,80 180,55" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="155" y="50" font-size="9" fill="#1a73e8">LRAC</text><line x1="110" y1="80" x2="110" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">MES</text><text x="40" y="105" font-size="7" fill="#16a34a">EoS</text><text x="140" y="40" font-size="7" fill="#dc2626">DoS</text></svg>', 5, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Give three causes of diseconomies of scale (with a real example).', 'Communication problems through many layers, coordination across divisions/countries, loss of motivation (workers feel like a small cog), principal-agent problem. RBS''s pre-2008 size, organisational complexity and risk-taking forced a £45.5bn UK government bailout — diseconomies in action.', 6, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Sketch the short-run cost curves (AFC, AVC, AC, MC).', 'AFC falls continuously; AVC and AC are U-shaped; MC cuts both AVC and AC at their minimums. Vertical gap between AC and AVC equals AFC. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q70,80 110,95 Q150,105 185,108" fill="none" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,2"/><text x="170" y="103" font-size="8" fill="#f59e0b">AFC</text><path d="M40,80 Q80,55 110,55 Q150,65 180,90" fill="none" stroke="#16a34a" stroke-width="1.5"/><text x="172" y="86" font-size="8" fill="#16a34a">AVC</text><path d="M40,55 Q80,35 115,40 Q150,50 180,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="172" y="71" font-size="8" fill="#1a73e8">AC</text><path d="M40,95 Q70,90 90,75 Q115,40 145,20" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="148" y="22" font-size="8" fill="#dc2626">MC</text></svg>', 7, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'State the law of diminishing returns.', 'In the short run, as additional units of a variable factor (labour) are added to a fixed factor (capital), beyond a point the marginal product falls. This is why MC and AVC eventually rise — short-run only, because the fixed factor becomes over-utilised.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Why is MR twice as steep as AR for a price-maker?', 'To sell one more unit, the firm must lower the price on ALL units, not just the extra one. MR therefore falls faster than AR. For a linear demand curve, MR has the same y-intercept but bisects the horizontal distance.', 9, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Distinguish normal and supernormal profit.', 'Normal profit: minimum return to keep the firm in the industry — opportunity cost of enterprise, included in TC, so TR = TC. Supernormal profit: TR > TC. Attracts new entrants in contestable markets; sustained behind barriers in monopoly/oligopoly.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'State the profit-maximising rule and the short-run shutdown condition.', 'Profit max: produce where MC = MR with MC rising through MR; price read up to AR. Short-run shutdown: AR < AVC — the firm should close. Long-run exit: AR < ATC.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Give three alternative business objectives to profit max with examples.', 'Revenue maximisation (MR=0) — Baumol: managers'' bonuses tied to sales. Sales maximisation (AR=ATC, normal-profit constraint) — Amazon ran losses for years building share. Satisficing — Simon: bounded rationality, "good enough" profit. Survival (start-ups, recessions). Social/ethical objectives (John Lewis Partnership, Patagonia).', 12, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Define the principal-agent problem and give one solution.', 'Owners (principals) want profit max; managers (agents) may pursue growth, perks or empire-building. Acute in PLCs with dispersed ownership — Kay Review found average UK shareholding fell from ~5 years (1960s) to <7 months. Solutions: performance pay, share options, NEDs, takeover threat.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '3.1', 'Business Economics', 'Why did Tesla illustrate long-run profit maximisation?', 'Tesla made losses for over a decade post-IPO (2010) while heavily investing in factories, batteries and software. Investors valued it above $1tn at peak (2021) on expected future EV dominance — short-run losses were consistent with long-run profit maximisation, not value destruction.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'List the four main market structures from most to least competitive.', 'Perfect competition, monopolistic competition, oligopoly, monopoly. They differ in number of firms, barriers to entry, product differentiation and price-setting power. UK examples: FX markets → restaurants → supermarkets/banks → Network Rail.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'State the assumptions of perfect competition.', 'Many small firms, homogeneous product, perfect information, no barriers to entry/exit, firms are price takers (AR = MR = P), profit maximisation. A theoretical benchmark — closest real examples are commodity and FX markets.', 2, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Why does perfect competition deliver only normal profit in the long run?', 'No barriers mean any supernormal profit attracts new entrants. Market supply shifts right, price falls until P = minimum AC and supernormal profit is competed away. Both allocative (P=MC) and productive (min AC) efficiency are achieved.', 3, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Sketch the monopoly profit-max diagram with supernormal profit and DWL.', 'MC=MR sets Qm; price Pm read up to AR. Supernormal profit = (Pm − AC) × Qm. DWL triangle between Qm and the allocatively efficient Qc (where MC=AR). <svg viewBox="0 0 200 150" width="180" height="135" style="display:block;margin:6px auto"><line x1="25" y1="125" x2="190" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="125" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="120" stroke="#16a34a" stroke-width="1.5"/><text x="183" y="123" font-size="8" fill="#16a34a">AR=D</text><line x1="35" y1="25" x2="107" y2="120" stroke="#f59e0b" stroke-width="1.5"/><text x="110" y="118" font-size="8" fill="#f59e0b">MR</text><path d="M35,100 Q70,90 100,75 Q130,55 165,30" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="167" y="32" font-size="8" fill="#dc2626">MC</text><path d="M35,80 Q80,55 110,52 Q150,60 175,80" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="178" y="84" font-size="8" fill="#1a73e8">AC</text><circle cx="80" cy="78" r="2" fill="#0B1E3F"/><line x1="80" y1="78" x2="80" y2="125" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="80" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="58" font-size="8" fill="#0B1E3F">Pm</text><text x="74" y="138" font-size="8" fill="#0B1E3F">Qm</text><rect x="35" y="55" width="45" height="13" fill="#16a34a" fill-opacity="0.2"/><polygon points="80,55 80,78 115,72" fill="#dc2626" fill-opacity="0.25"/></svg>', 4, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Give one Schumpeterian argument FOR monopoly.', 'Supernormal profits fund R&D and "creative destruction" — without the prospect of monopoly profits (often patent-protected), firms have less incentive to innovate. Pharma patents protect ~20-year returns on drug development.', 5, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'How did the 2024 US Google ruling illustrate abuse of monopoly power?', 'Google holds ~92% of global search. A US federal court found in 2024 that Google maintained an illegal monopoly by paying Apple ~$26bn/year and Samsung to set Google as the default search engine — anti-competitive lock-in rather than competition on the merits.', 6, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Define a natural monopoly and give UK examples.', 'A market where LRAC keeps falling at the level of total demand, so one firm can supply more cheaply than two. Examples: water (Thames Water), rail network (Network Rail), electricity transmission (National Grid). Regulated by Ofwat/Ofgem to prevent abuse.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Define oligopoly and its key feature; give a UK example.', 'A few large firms with high concentration. The 4-firm UK supermarket concentration ratio is over 65% (Tesco 27%, Sainsbury''s 15%, Asda 14%, Morrisons 9%). Key feature: INTERDEPENDENCE — each firm''s decisions depend on rivals'' likely reactions.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Sketch the kinked demand curve (Sweezy model).', 'Above current price P*, demand is elastic (rivals don''t follow a price rise). Below, demand is inelastic (rivals match cuts). MR has a vertical discontinuity — explains price rigidity in oligopoly. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="40" y1="25" x2="105" y2="65" stroke="#16a34a" stroke-width="2"/><line x1="105" y1="65" x2="170" y2="110" stroke="#16a34a" stroke-width="2"/><text x="172" y="113" font-size="8" fill="#16a34a">D</text><circle cx="105" cy="65" r="2.5" fill="#0B1E3F"/><line x1="50" y1="40" x2="105" y2="80" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="105" x2="135" y2="115" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="80" x2="105" y2="105" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="2,2"/><text x="138" y="115" font-size="8" fill="#f59e0b">MR</text><line x1="25" y1="65" x2="105" y2="65" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="68" font-size="8" fill="#0B1E3F">P*</text></svg>', 9, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Distinguish overt from tacit collusion.', 'Overt: explicit price/output cartel agreement (e.g. OPEC) — illegal under UK Competition Act 1998 and Article 101 TFEU. Tacit: parallel pricing or following a price leader, no formal agreement — harder to prosecute. CMA fined UK supermarkets for tacit dairy-price collusion in 2007.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Explain the prisoner''s dilemma in oligopoly.', 'Each firm''s dominant strategy is to undercut, even though both would gain from cooperating at high prices. The Nash equilibrium is (Low, Low) — suboptimal. Repeated games and tit-for-tat strategies make tacit collusion sustainable in stable oligopolies.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'How did the CMA''s 2023 UK fuel investigation illustrate oligopoly behaviour?', 'CMA found "rocket and feather" pricing — petrol prices rise quickly when wholesale costs rise but fall slowly when they decline. Retail-wholesale margins widened. No formal collusion was proven, but the oligopoly structure (Tesco, Asda, BP, Shell, etc.) and interdependence let firms keep margins higher than a competitive market would allow.', 12, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Define a contestable market and what disciplines incumbents.', 'A market with freedom of entry/exit and low or zero sunk costs, with the threat of "hit and run" entry. The threat of competition is as powerful as actual competition — even a monopolist must charge near competitively. EU airline deregulation (1990s) brought Ryanair/EasyJet onto BA/Lufthansa routes, but Heathrow slot scarcity limits contestability.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'Define monopsony in the labour market and give an example.', 'A market with a single (or dominant) buyer of labour — the employer faces an upward-sloping supply of labour and exploits its power by hiring fewer workers at lower wages. Examples: NHS as the dominant buyer of doctors/nurses; large supermarket chains for farm produce.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '3.2', 'Market Structures & Competition', 'How can the National Living Wage cause both higher wages and higher employment?', 'In a competitive labour market a binding minimum wage creates excess supply of labour. In a monopsonistic market (e.g. UK NLW £11.44/hr from April 2024 in supermarket and care work), a moderate wage floor counters employer power and can raise BOTH wages and employment.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Define globalisation and give two main causes.', 'The increasing integration and interdependence of economies through trade, FDI, migration and technology. Causes: lower trade barriers (WTO — average tariffs from ~40% to ~3%), containerisation cutting shipping costs ~90%, ICT/internet, financial deregulation, post-1989 opening of China and Eastern Europe.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Distinguish absolute and comparative advantage.', 'Absolute (Adam Smith): producing more output per unit of input than another country. Comparative (Ricardo): producing at lower opportunity cost. Mutually beneficial trade exists wherever opportunity costs differ — even if one country has absolute advantage in everything.', 2, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Give a worked comparative-advantage example with PPFs.', 'UK: 10 cloth or 5 wine/hr (OC of 1 cloth = 0.5 wine). Portugal: 8 cloth or 8 wine/hr (OC of 1 cloth = 1 wine). UK has CA in cloth; Portugal in wine. Both gain if UK specialises in cloth and Portugal in wine, then trade. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="55" x2="160" y2="115" stroke="#1a73e8" stroke-width="2"/><text x="55" y="50" font-size="8" fill="#1a73e8">UK</text><line x1="25" y1="35" x2="135" y2="115" stroke="#dc2626" stroke-width="2"/><text x="100" y="40" font-size="8" fill="#dc2626">Portugal</text><text x="6" y="65" font-size="9" fill="#0B1E3F">Wine</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Cloth</text></svg>', 3, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Give three limitations of the comparative advantage model.', 'Assumes constant opportunity costs (linear PPFs), no transport costs, perfect factor mobility within countries, no externalities, only two goods/two countries, free trade. Static — ignores dynamic shifts (e.g. South Korea moving from textiles to semiconductors).', 4, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Sketch a tariff diagram and label key areas.', 'World price Pw rises to Pw+t. Domestic supply rises Q1→Q2; demand falls Q4→Q3; imports = Q3−Q2. Government revenue = t × (Q3−Q2); two DWL triangles for production and consumption inefficiency. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="110" x2="170" y2="20" stroke="#1a73e8" stroke-width="1.8"/><text x="172" y="22" font-size="8" fill="#1a73e8">Sd</text><line x1="35" y1="25" x2="170" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="172" y="113" font-size="8" fill="#dc2626">D</text><line x1="25" y1="95" x2="180" y2="95" stroke="#16a34a" stroke-width="1.5"/><text x="160" y="92" font-size="7" fill="#16a34a">Pw</text><line x1="25" y1="80" x2="180" y2="80" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="3,2"/><text x="155" y="77" font-size="7" fill="#f59e0b">Pw+t</text><line x1="50" y1="95" x2="50" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="70" y1="80" x2="70" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="135" y1="80" x2="135" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="155" y1="95" x2="155" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><rect x="70" y="80" width="65" height="15" fill="#f59e0b" fill-opacity="0.25"/><text x="83" y="91" font-size="7" fill="#b45309">Govt rev</text><polygon points="50,95 70,95 70,80" fill="#dc2626" fill-opacity="0.3"/><polygon points="135,95 155,95 135,80" fill="#dc2626" fill-opacity="0.3"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 5, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Distinguish a tariff from a quota.', 'Tariff: tax on imports — raises domestic price, generates government revenue. Quota: physical limit on import quantity — also raises price but the rent goes to whoever holds import licences (no government revenue). Both create DWL.', 6, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Give three arguments for protectionism.', 'Infant industry (until economies of scale achieved), strategic industries (defence, food, energy security), anti-dumping (counter foreign sales below cost), preventing structural unemployment, government revenue (key for developing countries with weak tax systems), upholding environmental/labour standards.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Distinguish a customs union from a free-trade area, and the EU Single Market.', 'Free-trade area: members eliminate internal tariffs but set their own external tariffs (USMCA, EFTA). Customs union: also has a Common External Tariff with non-members. Single Market: customs union + free movement of goods, services, capital and labour (EU SM). Eurozone adds a single currency.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Define trade creation vs trade diversion.', 'Trade creation: joining a bloc shifts demand from a high-cost domestic producer to a lower-cost member producer — welfare-improving. Trade diversion: shifts demand from a lower-cost non-member producer to a higher-cost member producer because of the CET — welfare-reducing. Net effect depends which is larger.', 9, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Sketch an exchange-rate appreciation of sterling.', 'Demand for £ rises (e.g. higher UK rates attract hot money). Equilibrium $/£ rises. Effect: exports dearer abroad, imports cheaper. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="160" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="163" y="113" font-size="8" fill="#dc2626">D£1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="4,3"/><text x="178" y="98" font-size="8" fill="#dc2626">D£2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="28" font-size="8" fill="#1a73e8">S£</text><circle cx="92" cy="72" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="57" r="2.5" fill="#0B1E3F"/><text x="6" y="55" font-size="8" fill="#0B1E3F">$/£</text><text x="100" y="130" font-size="8" fill="#0B1E3F">Q£</text></svg>', 10, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'State the Marshall-Lerner condition and the J-curve.', 'A depreciation improves the current account if |PEDx| + |PEDm| > 1. J-curve: in the short run, contracts and adjustment lags mean import bills rise first and the deficit worsens; only later as volumes adjust does the CA improve, tracing a J shape.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'How did Brexit illustrate exchange-rate effects and non-tariff barriers?', 'After the June 2016 vote sterling fell from ~$1.50 to ~$1.32 within 24 hours; UK CPI rose from 0.5% (June 2016) to 3.0% (Sept 2017) via dearer imports. Post-2021, customs declarations, rules-of-origin checks and SPS inspections cut UK-EU goods trade an estimated ~7% (CER) — non-tariff barriers can be as costly as tariffs.', 12, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Give one cost of the 2018-19 US-China trade war.', 'Trump tariffs of up to 25% on ~$370bn of Chinese imports, plus Chinese retaliation. Federal Reserve Bank of NY estimated ~$831/year cost per US household in higher prices; US soybean exports to China fell ~75%; global supply chains and investment took a hit.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'List four arguments against protectionism.', 'Higher prices and reduced choice for consumers; retaliation/trade wars; protected firms become inefficient (X-inefficiency); resource misallocation away from comparative advantage; infant industry protection often becomes permanent; deadweight welfare loss.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '4.1', 'International Economics & Globalisation', 'Outline the WTO and a key limitation.', 'Established 1995 (replacing GATT), 164 members. Key principles: Most Favoured Nation (no discrimination), national treatment, reciprocity, transparency. Limitation: the Doha Round (2001-) has stalled — consensus among 164 members is hard, and bilateral/regional FTAs have proliferated, undermining multilateralism.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Distinguish economic growth from economic development.', 'Growth: quantitative — increase in real GDP. Development: qualitative — improvements in living standards, health, education, freedoms and sustainability. Growth is necessary but not sufficient — Saudi Arabia has very high GDP per capita but a much lower HDI rank than Japan due to gender, freedoms and oil dependence.', 1, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'List four indicators of development beyond GDP per capita.', 'HDI (life expectancy + schooling + GNI/capita PPP), IHDI (inequality-adjusted), Multidimensional Poverty Index (MPI), Gender Inequality Index (GII), infant mortality, literacy rate, access to clean water.', 2, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'What does the HDI measure and how is it scored?', 'A 0-1 composite: (1) life expectancy at birth, (2) mean and expected years of schooling, (3) GNI per capita (PPP, logged). Switzerland 0.962, UK 0.929, China 0.768, India 0.644, Niger 0.400. Captures health, education and income but ignores inequality, environment and freedoms.', 3, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Distinguish absolute from relative poverty.', 'Absolute: income too low to meet basic needs — World Bank line is $2.15/day (2022 PPP); ~700 million people remain below it. Relative: below 60% of median household income (UK definition). A person can be relatively poor in the UK without being absolutely poor.', 4, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Sketch a Lorenz curve and explain the Gini coefficient.', 'Cumulative %income (y) vs cumulative %population (x). Diagonal = perfect equality; Lorenz sags below it. Gini = Area A / (Area A + Area B), 0 (equal) to 1 (one person has all). UK ~0.35; Sweden ~0.29; South Africa ~0.63. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="180" y2="20" stroke="#64748b" stroke-width="1" stroke-dasharray="3,3"/><text x="120" y="55" font-size="7" fill="#64748b">equality</text><path d="M25,115 Q90,108 130,80 Q160,55 180,20" fill="none" stroke="#dc2626" stroke-width="2"/><text x="100" y="100" font-size="8" fill="#dc2626">Lorenz</text><text x="60" y="80" font-size="8" fill="#0B1E3F">A</text><text x="130" y="55" font-size="8" fill="#0B1E3F">B</text><text x="40" y="130" font-size="8" fill="#0B1E3F">% pop</text><text x="6" y="65" font-size="8" fill="#0B1E3F">%Y</text></svg>', 5, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Sketch the Kuznets curve.', 'Inverted-U: inequality rises in early industrialisation as workers shift to higher-paid modern sector, peaks, then falls as education spreads, the welfare state develops and demand for skilled labour rises. Empirically contested — UK and US inequality has risen since the 1980s. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,100 Q70,30 105,30 Q150,30 180,100" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="80" y="40" font-size="8" fill="#1a73e8">Kuznets</text><text x="6" y="65" font-size="8" fill="#0B1E3F">Gini</text><text x="80" y="130" font-size="8" fill="#0B1E3F">GDP/capita</text></svg>', 6, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Give three problems caused by primary product dependency.', 'Price volatility (commodity swings of 50%+), Prebisch-Singer (declining terms of trade for primaries vs manufactures), Dutch Disease (resource boom appreciates currency, hurts other exporters), resource curse (corruption, conflict — Nigeria lost ~$400bn to corruption 1960-1999), low value-added.', 7, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'How does the resource curse explain Nigeria''s low HDI?', 'Africa''s largest economy by GDP, abundant oil/gas, yet HDI only 0.535. Oil revenues fuelled corruption (~$400bn lost 1960-1999), suppressed non-oil industries (Dutch Disease), and entrenched elites. Life expectancy ~55 years; 63% in multidimensional poverty — natural wealth is neither necessary nor sufficient for development.', 8, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Outline the poverty trap (cycle of poverty).', 'Self-reinforcing cycle: low income → low savings/investment in human capital → poor education and health → low productivity → continued low income. Breaking any link is the goal — conditional cash transfers (Bolsa Família), microfinance, healthcare access and education investment.', 9, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Outline the role of microfinance in development, with one limitation.', 'Small loans/savings/insurance for poor entrepreneurs without collateral — pioneered by Grameen Bank in Bangladesh (Yunus, Nobel 2006). Empowers women, supports informal businesses. Limitation: high effective interest rates, debt traps and mixed RCT evidence on transformative poverty reduction.', 10, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Distinguish tied from untied aid; bilateral from multilateral.', 'Tied: must be spent on donor-country goods/services — boosts donor industries but may be poor value. Untied: recipient chooses suppliers — generally more effective. Bilateral: country to country. Multilateral: through bodies like the World Bank, IMF or UN.', 11, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Why was South Korea''s post-1960 transformation so remarkable?', 'In 1960 Korean GDP/capita was similar to Ghana''s; today GDP/capita PPP is over $50,000 and HDI 0.929. Combined: massive education investment (near-universal literacy by the 1970s), export-led industrialisation in shipbuilding/steel/electronics/cars, land reform reducing inequality, and high savings/investment rates.', 12, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Distinguish import-substitution from export-led growth.', 'ISI: replace imports with domestic production behind tariffs/quotas — Latin America, India 1950s-80s. Risks: protected firms remain inefficient, market too small. Export-led: produce for global markets, exploit CA, attract FDI — East Asian Tigers (Korea, Taiwan, Singapore, Hong Kong). Generally more successful empirically.', 13, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'How did Bolsa Família reduce poverty in Brazil?', 'Conditional cash transfers from 2003 paying poor families if children attended school and got health checks. By 2014 covered 14 million families (~50m people) at <0.5% of GDP. Extreme poverty fell from 9.7% to 4.3%; Gini fell 0.59 → 0.53. Structural inequality (land, race) remained — CCTs alone are not enough.', 14, 'alevel'),
  ('Economics', 'Edexcel B', '4.2', 'Development & Inequality', 'Evaluate progressive taxation as an inequality-reducing policy.', 'Effective at redistribution; UK rates 0/20/40/45%. But very high marginal rates may cut work and enterprise incentives (Laffer argument), encourage avoidance/evasion, and reduce growth. Pre-distribution policies (education, competition policy, labour-market reform) tackle inequality at source rather than only after the fact.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Define the economic problem and the three questions it forces every society to answer.', 'Scarcity — wants are unlimited but resources finite — forces choices about what to produce, how to produce it, and for whom to produce it.', 1, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Define opportunity cost and give one government example.', 'The value of the next best alternative forgone when a choice is made. E.g. £370bn of UK COVID-19 support meant delays to HS2, Crossrail and constrained future health/education spending.', 2, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Name the four factors of production and their factor rewards.', 'Land (rent), labour (wages), capital (interest), enterprise (profit). Capital here means physical/produced inputs (factories, machinery), not money.', 3, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Sketch a PPF and label efficient, inefficient and unattainable points.', 'Concave curve. ON the curve = productively efficient; INSIDE = inefficient (recession, unemployment); OUTSIDE = currently unattainable. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,25 Q175,25 180,115" fill="none" stroke="#1a73e8" stroke-width="2"/><circle cx="80" cy="55" r="3" fill="#16a34a"/><text x="86" y="52" font-size="8" fill="#16a34a">A</text><circle cx="70" cy="95" r="3" fill="#f59e0b"/><text x="76" y="98" font-size="8" fill="#f59e0b">B</text><circle cx="160" cy="45" r="3" fill="#dc2626"/><text x="166" y="43" font-size="8" fill="#dc2626">C</text><text x="80" y="132" font-size="9" fill="#0B1E3F">Consumer goods</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Capital</text></svg>', 4, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Why does a PPF bow outwards from the origin?', 'Increasing opportunity cost: as output of one good rises, ever more units of the other must be given up because resources are not perfectly substitutable between uses.', 5, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Compare a free-market, a command and a mixed economy.', 'Free market: private ownership and prices set by S&D (e.g. Hong Kong). Command: state ownership and central planning (e.g. North Korea). Most real economies, including the UK, are mixed — markets plus state provision (NHS, defence) and intervention.', 6, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'State the three functions of the price mechanism.', 'Signalling (prices convey scarcity), incentive (high prices reward more supply and discourage demand), and rationing (allocating scarce goods to those willing and able to pay).', 7, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Sketch market equilibrium showing consumer and producer surplus.', 'D and S cross at (Pe, Qe). CS is the triangle below D above Pe; PS is above S below Pe. Total welfare = CS + PS, maximised at the free-market equilibrium absent failure. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><polygon points="35,25 107,67 25,67" fill="#16a34a" fill-opacity="0.15"/><polygon points="35,110 107,67 25,67" fill="#1a73e8" fill-opacity="0.15"/><circle cx="107" cy="67" r="2.5" fill="#0B1E3F"/><line x1="25" y1="67" x2="107" y2="67" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><line x1="107" y1="67" x2="107" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="10" y="70" font-size="9" fill="#0B1E3F">Pe</text><text x="103" y="128" font-size="9" fill="#0B1E3F">Qe</text><text x="60" y="55" font-size="8" fill="#16a34a">CS</text><text x="60" y="92" font-size="8" fill="#1a73e8">PS</text></svg>', 8, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'List four non-price factors that shift demand right.', 'Higher real income (normal goods), rising price of a substitute, falling price of a complement, favourable tastes/advertising, rising population, expectations of future price rises, lower interest rates on credit goods.', 9, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Show on a diagram what happens when supply shifts left while demand is fixed.', 'New equilibrium: higher price, lower quantity. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="170" y2="25" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="160" y="22" font-size="9" fill="#1a73e8">S1</text><line x1="35" y1="90" x2="140" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="50" y="50" font-size="9" fill="#1a73e8">S2</text><circle cx="100" cy="66" r="2.5" fill="#0B1E3F"/><circle cx="80" cy="55" r="2.5" fill="#0B1E3F"/><line x1="100" y1="66" x2="80" y2="55" stroke="#64748b" stroke-width="0.8"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 10, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'State the formula for PED and what the absolute value tells you.', 'PED = % change in Qd ÷ % change in P (always negative). |PED| > 1 = elastic; |PED| < 1 = inelastic; |PED| = 1 = unit elastic.', 11, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Sketch elastic vs inelastic demand on the same axes.', 'Elastic D is relatively flat; inelastic D is relatively steep. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="50" x2="180" y2="80" stroke="#16a34a" stroke-width="2"/><text x="155" y="45" font-size="8" fill="#16a34a">elastic</text><line x1="95" y1="20" x2="125" y2="115" stroke="#dc2626" stroke-width="2"/><text x="128" y="40" font-size="8" fill="#dc2626">inelastic</text><text x="10" y="65" font-size="9" fill="#0B1E3F">P</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 12, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'If demand is price-inelastic, what should a firm do to maximise revenue?', 'Raise the price. With |PED| < 1, the percentage fall in Qd is smaller than the percentage rise in P, so total revenue (P x Q) rises. Firms with elastic demand should cut prices instead.', 13, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'Distinguish YED for normal, luxury and inferior goods.', 'YED = %ΔQd ÷ %ΔY. Normal: YED > 0. Luxury (superior): YED > 1 (e.g. LVMH). Necessity: 0 < YED < 1 (bread, milk). Inferior: YED < 0 (supermarket value ranges, bus travel).', 14, 'alevel'),
  ('Economics', 'OCR', '1.1', 'Economic Problem & Market Systems', 'What does cross elasticity of demand (XED) reveal?', 'The relationship between two goods. Positive XED = substitutes (Coke and Pepsi); negative XED = complements (printers and ink); XED ≈ 0 = unrelated. Magnitude indicates strength of relationship.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Define market failure and state the social-optimum condition.', 'Market failure occurs when the free market mechanism leads to a misallocation of resources and net welfare loss. The socially optimal output is where MSB = MSC.', 1, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'List four main causes of market failure.', 'Externalities, public goods, merit/demerit goods (information failure), monopoly power, factor immobility, and inequality.', 2, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Sketch a negative production externality with welfare loss shaded.', 'MSC lies above MPC. Free market produces at Q1 (where MPC=MSB) but social optimum is Q* (MSC=MSB). Triangle between Q* and Q1 is the deadweight welfare loss. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="32" font-size="8" fill="#1a73e8">MPC</text><line x1="35" y1="80" x2="180" y2="20" stroke="#dc2626" stroke-width="1.8"/><text x="158" y="18" font-size="8" fill="#dc2626">MSC</text><line x1="35" y1="30" x2="180" y2="100" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="105" font-size="8" fill="#16a34a">MSB</text><circle cx="115" cy="68" r="2" fill="#1a73e8"/><circle cx="100" cy="60" r="2" fill="#dc2626"/><line x1="115" y1="68" x2="115" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="60" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="110" y="128" font-size="8" fill="#1a73e8">Q1</text><text x="92" y="128" font-size="8" fill="#dc2626">Q*</text><polygon points="100,60 115,68 115,52" fill="#dc2626" fill-opacity="0.25"/></svg>', 3, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Sketch a positive consumption externality.', 'MSB lies above MPB; market under-consumes at Q1 versus social optimum Q*. Welfare loss between Q1 and Q*. Example: vaccination, education. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="105" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="32" font-size="8" fill="#1a73e8">MSC</text><line x1="35" y1="35" x2="170" y2="105" stroke="#dc2626" stroke-width="1.8"/><text x="158" y="115" font-size="8" fill="#dc2626">MPB</text><line x1="35" y1="20" x2="180" y2="95" stroke="#16a34a" stroke-width="1.8" stroke-dasharray="3,2"/><text x="158" y="92" font-size="8" fill="#16a34a">MSB</text><line x1="95" y1="68" x2="95" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="115" y1="58" x2="115" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="88" y="128" font-size="8" fill="#dc2626">Q1</text><text x="112" y="128" font-size="8" fill="#16a34a">Q*</text><polygon points="95,68 115,58 115,75" fill="#16a34a" fill-opacity="0.25"/></svg>', 4, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'State the two characteristics of a pure public good.', 'Non-excludable (cannot prevent non-payers consuming) and non-rivalrous (one person''s use doesn''t reduce availability for others). Examples: defence, street lighting, flood defences, lighthouses.', 5, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Explain the free-rider problem.', 'Because public goods are non-excludable, individuals can consume without paying. Rational agents will not pay voluntarily, so private firms cannot charge a price and the good is not supplied — a complete market failure. Solved by state provision funded by taxation.', 6, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Distinguish merit goods from demerit goods.', 'Merit goods (education, healthcare, vaccinations) are under-consumed due to information failure and positive externalities. Demerit goods (tobacco, alcohol, gambling) are over-consumed due to information failure and negative externalities.', 7, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Distinguish asymmetric from imperfect information.', 'Asymmetric: one party knows more than the other (used car "lemons", patient vs doctor). Imperfect: neither party has full knowledge (long-term effects of new food additives). Both lead to misallocation.', 8, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Sketch the effect of a specific indirect tax on a demerit good.', 'Specific tax shifts S left by a parallel UP shift equal to the tax per unit. Price rises from P1 to P2; quantity falls from Q1 to Q2. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="105" x2="180" y2="30" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="170" y="28" font-size="9" fill="#1a73e8">S1</text><line x1="35" y1="80" x2="180" y2="10" stroke="#1a73e8" stroke-width="2"/><text x="183" y="14" font-size="9" fill="#1a73e8">S2</text><circle cx="107" cy="68" r="2.5" fill="#0B1E3F"/><circle cx="86" cy="55" r="2.5" fill="#0B1E3F"/><line x1="86" y1="55" x2="86" y2="79" stroke="#f59e0b" stroke-width="2"/><text x="90" y="70" font-size="8" fill="#f59e0b">tax</text><line x1="25" y1="68" x2="107" y2="68" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="86" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="71" font-size="8" fill="#0B1E3F">P1</text><text x="9" y="58" font-size="8" fill="#0B1E3F">P2</text><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 9, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'How is the burden of an indirect tax distributed when demand is inelastic?', 'Most of the tax burden falls on consumers (price rises sharply, Qd barely falls). This is why the UK can raise large revenues from taxes on cigarettes, petrol and alcohol — demand is highly inelastic.', 10, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Sketch the effect of a subsidy on a merit good.', 'Subsidy shifts S right (parallel down shift) by the subsidy per unit. Price falls; quantity rises. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="100" x2="180" y2="20" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="170" y="20" font-size="9" fill="#1a73e8">S1</text><line x1="35" y1="115" x2="180" y2="35" stroke="#16a34a" stroke-width="2"/><text x="183" y="42" font-size="9" fill="#16a34a">S2</text><circle cx="100" cy="65" r="2.5" fill="#0B1E3F"/><circle cx="115" cy="78" r="2.5" fill="#0B1E3F"/><text x="80" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 11, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Sketch a maximum price (price ceiling) and explain its effect.', 'Pmax set BELOW equilibrium creates a shortage: Qd > Qs. Used for affordability, e.g. rent controls. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><line x1="25" y1="85" x2="180" y2="85" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="3,2"/><text x="155" y="82" font-size="8" fill="#f59e0b">Pmax</text><line x1="70" y1="85" x2="70" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="148" y1="85" x2="148" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="60" y="128" font-size="8" fill="#0B1E3F">Qs</text><text x="142" y="128" font-size="8" fill="#0B1E3F">Qd</text><text x="90" y="100" font-size="8" fill="#dc2626">shortage</text></svg>', 12, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Why does the UK National Minimum Wage create potential unemployment?', 'NMW is a price floor set above the labour-market equilibrium wage. At the higher wage, labour supply (Qs) exceeds labour demand (Qd) — the gap is classical/real-wage unemployment. Effect depends on monopsony power and elasticity.', 13, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'How do tradeable pollution permits work?', 'Government caps total emissions and issues permits; firms can trade them. Low-cost abaters sell spare permits to high-cost polluters. The EU ETS covers ~40% of EU GHGs; permit prices rose above 80 euros/tonne by 2023 after Market Stability Reserve reforms.', 14, 'alevel'),
  ('Economics', 'OCR', '1.2', 'Market Failure & Government Intervention', 'Define government failure and give one cause.', 'Where intervention to correct market failure leads to a net welfare loss. Causes: distorted price signals, unintended consequences (rent controls reducing supply), regulatory capture, political short-termism, information gaps when setting tax/subsidy levels.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'State the profit-maximising rule and explain why.', 'Produce where MC = MR (MC rising through MR). At any output below this, MR > MC so an extra unit adds to profit; above it, MC > MR so producing more reduces profit.', 1, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'State the conditions for revenue maximisation and sales maximisation.', 'Revenue max: where MR = 0 (TR is at its peak). Sales max (Baumol): largest output subject to AC = AR (normal-profit constraint), so larger Q and lower P than revenue max.', 2, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'What is satisficing and which problem does it relate to?', 'Simon: managers settle for "good enough" profits while balancing stakeholder demands. Linked to the principal-agent problem — managers (agents) may pursue salary, prestige or an easy life rather than max profit for shareholders (principals).', 3, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Distinguish fixed and variable costs with examples.', 'Fixed costs do not vary with output (rent, insurance, business rates) and are paid even at zero output. Variable costs do vary with output (raw materials, hourly wages, energy, packaging).', 4, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'State the law of diminishing marginal returns and its time horizon.', 'In the SHORT RUN, as successive units of a variable factor (e.g. labour) are added to a fixed factor (e.g. capital), marginal product eventually falls. Explains the U-shape of SR cost curves. Long-run concept is returns to scale.', 5, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Sketch the short-run cost curves (AFC, AVC, AC, MC).', 'AFC falls continuously; AVC and AC are U-shaped; MC cuts both AVC and AC at their minimums. Gap between AC and AVC = AFC. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q70,80 110,95 Q150,105 185,108" fill="none" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="4,2"/><text x="170" y="103" font-size="8" fill="#f59e0b">AFC</text><path d="M40,80 Q80,55 110,55 Q150,65 180,90" fill="none" stroke="#16a34a" stroke-width="1.5"/><text x="172" y="86" font-size="8" fill="#16a34a">AVC</text><path d="M40,55 Q80,35 115,40 Q150,50 180,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="172" y="71" font-size="8" fill="#1a73e8">AC</text><path d="M40,95 Q70,90 90,75 Q115,40 145,20" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="148" y="22" font-size="8" fill="#dc2626">MC</text><text x="100" y="130" font-size="9" fill="#0B1E3F">Q</text></svg>', 6, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Why does MC cross AC at the minimum point of AC?', 'When MC < AC, the next unit pulls the average down. When MC > AC, it pulls the average up. So AC must be at its minimum exactly where MC = AC — same logic as test grades pulling an average up or down.', 7, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'List four internal economies of scale.', 'Technical (specialised capital like blast furnaces, container ships), managerial (specialist managers), purchasing (bulk discounts — Tesco vs corner shop), financial (cheaper borrowing), marketing (advertising spread over more units), risk-bearing (Unilever''s diversified brands).', 8, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Sketch the LRAC envelope curve and label MES.', 'LRAC envelopes a series of SRACs. Falling section = economies of scale; flat = constant returns; rising = diseconomies. MES is the lowest output where LRAC reaches its minimum. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,40 Q75,80 110,80 Q145,80 180,55" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="155" y="50" font-size="9" fill="#1a73e8">LRAC</text><path d="M35,40 Q60,75 90,90" fill="none" stroke="#94a3b8" stroke-width="1" stroke-dasharray="3,2"/><path d="M70,75 Q105,75 130,90" fill="none" stroke="#94a3b8" stroke-width="1" stroke-dasharray="3,2"/><path d="M125,80 Q160,75 180,55" fill="none" stroke="#94a3b8" stroke-width="1" stroke-dasharray="3,2"/><line x1="110" y1="80" x2="110" y2="115" stroke="#64748b" stroke-width="0.8" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">MES</text><text x="40" y="105" font-size="7" fill="#16a34a">EoS</text><text x="140" y="40" font-size="7" fill="#dc2626">DoS</text><text x="100" y="138" font-size="9" fill="#0B1E3F">Q</text></svg>', 9, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Give two diseconomies of scale.', 'Communication problems (information distorted across many management layers), coordination difficulties, loss of motivation in very large organisations, bureaucracy slowing decisions. Boeing 737 MAX crisis cited as a real-world example.', 10, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Distinguish diminishing marginal returns from decreasing returns to scale.', 'Diminishing returns: SHORT RUN, one factor fixed — explains U-shaped SR cost curves. Decreasing returns to scale: LONG RUN, all factors increase together — explains rising LRAC. OCR examiners flag confusion between them.', 11, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'Define normal and supernormal profit.', 'Normal profit: minimum return required to keep the firm in the industry, included as a cost (TR = TC, AR = AC). Supernormal profit: profit above normal (TR > TC), which signals new firms to enter unless barriers exist.', 12, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'For a price-making firm, why does MR lie below AR and fall twice as fast?', 'To sell one extra unit the firm must lower the price on ALL units, so MR from the next sale is less than its price (AR). For a linear demand curve, MR has the same y-intercept but twice the gradient.', 13, 'alevel'),
  ('Economics', 'OCR', '1.3', 'Firm Objectives, Costs & Revenue', 'State the short-run shutdown condition.', 'Continue producing in the short run if AR ≥ AVC — revenue covers variable costs and contributes to fixed costs. Shut down immediately if AR < AVC. In the long run all costs must be covered (AR ≥ ATC).', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '1.4', 'Market Structures', 'List the four main market structures from most to least competitive.', 'Perfect competition, monopolistic competition, oligopoly, monopoly. They differ in number of firms, barriers to entry, product differentiation and price-setting power.', 1, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'State the assumptions of perfect competition.', 'Many small buyers and sellers, homogeneous product, perfect information, free entry/exit, no transport costs, profit-maximising firms. Each firm is a price taker facing a horizontal AR=MR=D at the market price.', 2, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Sketch long-run equilibrium in perfect competition.', 'Free entry erodes any supernormal profit, so AR is tangent to ATC at its minimum: P = MC = min ATC, only normal profit. Both allocative and productive efficiency achieved. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,95 Q75,80 105,65 Q140,40 175,15" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="178" y="18" font-size="8" fill="#dc2626">MC</text><path d="M35,75 Q80,55 105,55 Q140,60 178,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="180" y="78" font-size="8" fill="#1a73e8">AC</text><line x1="25" y1="55" x2="180" y2="55" stroke="#16a34a" stroke-width="1.8"/><text x="155" y="50" font-size="8" fill="#16a34a">AR=MR=D</text><circle cx="105" cy="55" r="2.5" fill="#0B1E3F"/><line x1="105" y1="55" x2="105" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">Q*</text></svg>', 3, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Why does perfect competition deliver only normal profit in the long run?', 'No barriers to entry mean any short-run supernormal profit attracts new firms. Market supply shifts right, price falls until P = min ATC and supernormal profit is competed away.', 4, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'What share of the market defines monopoly power under UK competition law?', '25% or more — the working definition used by the CMA. Pure (single-firm) monopoly is rare; the CMA also blocks mergers (e.g. the 2019 Sainsbury''s-Asda merger) where reduced competition would harm consumers.', 5, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'List four sources of monopoly power (barriers to entry).', 'Economies of scale / natural monopoly, legal barriers (patents, licences), brand loyalty, control of essential resources, network effects (Meta, WhatsApp), high sunk costs, predatory pricing.', 6, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Sketch monopoly profit-maximisation with supernormal profit and DWL.', 'Profit max at MC=MR; price Pm read off AR above this output; ATC at Qm gives unit cost. Supernormal profit = (Pm-AC) x Qm. DWL is the triangle between Qm and the allocative-efficient Qc where MC=AR. <svg viewBox="0 0 200 150" width="180" height="135" style="display:block;margin:6px auto"><line x1="25" y1="125" x2="190" y2="125" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="125" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="120" stroke="#16a34a" stroke-width="1.5"/><text x="183" y="123" font-size="8" fill="#16a34a">AR=D</text><line x1="35" y1="25" x2="107" y2="120" stroke="#f59e0b" stroke-width="1.5"/><text x="110" y="118" font-size="8" fill="#f59e0b">MR</text><path d="M35,100 Q70,90 100,75 Q130,55 165,30" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="167" y="32" font-size="8" fill="#dc2626">MC</text><path d="M35,80 Q80,55 110,52 Q150,60 175,80" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="178" y="84" font-size="8" fill="#1a73e8">AC</text><circle cx="80" cy="78" r="2" fill="#0B1E3F"/><line x1="80" y1="55" x2="80" y2="125" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="80" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="11" y="58" font-size="8" fill="#0B1E3F">Pm</text><text x="74" y="138" font-size="8" fill="#0B1E3F">Qm</text><rect x="35" y="55" width="45" height="13" fill="#16a34a" fill-opacity="0.2"/><polygon points="80,55 80,78 115,72" fill="#dc2626" fill-opacity="0.25"/><text x="90" y="70" font-size="7" fill="#dc2626">DWL</text></svg>', 7, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'State Schumpeter''s argument FOR monopoly.', 'Supernormal profits fund R&D and innovation, driving "creative destruction." Without the prospect of monopoly profits — particularly via patents — firms have less incentive to develop new products. Strong dynamic-efficiency case.', 8, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Define a natural monopoly with a UK example.', 'A market where LRAC is still falling at the level of total market demand, so one firm can supply the whole market more cheaply than two. UK examples: water (Thames Water, Severn Trent), electricity transmission, Network Rail. Regulated by Ofwat/Ofgem.', 9, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Sketch a monopolistically competitive firm in long-run equilibrium.', 'Many firms with low entry barriers — supernormal profits attract entry, demand shifts left until AR is tangent to ATC. Normal profit only; P > MC (allocatively inefficient) and excess capacity (P > min ATC). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M35,95 Q75,80 100,60 Q130,35 170,15" fill="none" stroke="#dc2626" stroke-width="1.5"/><text x="173" y="18" font-size="8" fill="#dc2626">MC</text><path d="M35,75 Q80,55 105,55 Q140,60 178,75" fill="none" stroke="#1a73e8" stroke-width="1.5"/><text x="180" y="78" font-size="8" fill="#1a73e8">AC</text><line x1="35" y1="30" x2="178" y2="105" stroke="#16a34a" stroke-width="1.5"/><text x="180" y="108" font-size="8" fill="#16a34a">AR</text><line x1="35" y1="30" x2="110" y2="105" stroke="#f59e0b" stroke-width="1.5"/><text x="115" y="108" font-size="8" fill="#f59e0b">MR</text><circle cx="85" cy="65" r="2.5" fill="#0B1E3F"/><line x1="85" y1="65" x2="85" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="80" y="128" font-size="8" fill="#0B1E3F">Q*</text></svg>', 10, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Define oligopoly and its key feature.', 'A market dominated by a few large interdependent firms (UK supermarkets, mobile networks, banks). Defining feature is INTERDEPENDENCE — each firm''s decisions depend on rivals'' likely reactions, leading to game-theory style strategy.', 11, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Sketch the kinked demand curve.', 'Sweezy: rivals match price cuts (D inelastic below P*) but ignore price rises (D elastic above P*), giving a kink at P*. MR has a vertical discontinuity, so MC can shift inside it without changing P* — explains price rigidity. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="35" x2="105" y2="65" stroke="#1a73e8" stroke-width="2"/><line x1="105" y1="65" x2="145" y2="110" stroke="#1a73e8" stroke-width="2"/><text x="148" y="113" font-size="9" fill="#1a73e8">D</text><line x1="35" y1="35" x2="100" y2="91" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="100" x2="115" y2="115" stroke="#f59e0b" stroke-width="1.5"/><line x1="105" y1="91" x2="105" y2="100" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="3,2"/><text x="118" y="115" font-size="8" fill="#f59e0b">MR</text><circle cx="105" cy="65" r="3" fill="#0B1E3F"/><line x1="25" y1="65" x2="105" y2="65" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="105" y1="65" x2="105" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="11" y="68" font-size="8" fill="#0B1E3F">P*</text><text x="100" y="128" font-size="8" fill="#0B1E3F">Q*</text></svg>', 12, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Distinguish overt collusion from tacit collusion.', 'Overt (cartel): explicit agreement to fix prices/output — illegal in the UK/EU. Tacit: informal coordination via price leadership or parallel pricing — harder to detect. Big incentive to cheat means cartels are unstable (prisoner''s dilemma).', 13, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Define a contestable market (Baumol).', 'A market with free entry and exit and very low sunk costs; the THREAT of hit-and-run entry forces incumbents to keep prices and costs low, even with few firms. Airline routes after deregulation are the classic example.', 14, 'alevel'),
  ('Economics', 'OCR', '1.4', 'Market Structures', 'Sketch a monopsony in the labour market.', 'Monopsony employer faces upward-sloping SL; MCL lies above SL because hiring one more worker requires raising wages for ALL workers. Profit-max hires where MRP = MCL, paying wage Wm BELOW the competitive We — fewer workers and lower wages. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="105" x2="180" y2="35" stroke="#1a73e8" stroke-width="1.8"/><text x="158" y="32" font-size="8" fill="#1a73e8">SL</text><line x1="35" y1="105" x2="160" y2="20" stroke="#dc2626" stroke-width="1.8"/><text x="155" y="18" font-size="8" fill="#dc2626">MCL</text><line x1="35" y1="25" x2="180" y2="105" stroke="#16a34a" stroke-width="1.8"/><text x="158" y="112" font-size="8" fill="#16a34a">MRP</text><circle cx="100" cy="56" r="2.5" fill="#0B1E3F"/><line x1="100" y1="56" x2="100" y2="78" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><circle cx="100" cy="78" r="2.5" fill="#1a73e8"/><line x1="25" y1="78" x2="100" y2="78" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="78" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="11" y="81" font-size="8" fill="#1a73e8">Wm</text><text x="92" y="128" font-size="8" fill="#0B1E3F">Lm</text></svg>', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Define GDP and give the expenditure-method formula.', 'GDP is the total value of goods and services produced within a country in a given period. Expenditure method: GDP = C + I + G + (X - M).', 1, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Distinguish nominal GDP from real GDP and explain why real is preferred.', 'Nominal GDP is at current prices and includes inflation. Real GDP uses constant base-year prices, stripping out price changes. Real GDP is preferred for comparing actual output over time.', 2, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'List three limitations of GDP per capita as a measure of living standards.', 'Ignores income distribution; misses informal/shadow economy and household production; ignores leisure, environment and externalities; not adjusted for purchasing power across countries (need PPP).', 3, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'What does the Human Development Index (HDI) include?', 'Three dimensions: life expectancy at birth, education (mean and expected years of schooling), and GNI per capita on PPP terms. Captures health and education alongside income, but still excludes inequality (IHDI fixes this) and environment.', 4, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Sketch the business cycle.', 'Real GDP fluctuates around the long-run trend: boom, slowdown, recession, recovery. Gap between actual and trend = output gap. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="100" x2="180" y2="30" stroke="#94a3b8" stroke-width="1.2" stroke-dasharray="3,3"/><text x="155" y="28" font-size="8" fill="#94a3b8">trend</text><path d="M30,90 Q55,50 80,75 Q105,100 130,55 Q155,15 180,40" fill="none" stroke="#1a73e8" stroke-width="2"/><text x="60" y="48" font-size="7" fill="#16a34a">boom</text><text x="100" y="105" font-size="7" fill="#dc2626">recession</text><text x="100" y="135" font-size="9" fill="#0B1E3F">Time</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Real GDP</text></svg>', 5, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Define a positive and a negative output gap.', 'Positive: actual GDP > potential GDP — economy overheating, inflationary pressure. Negative: actual GDP < potential GDP — spare capacity, low inflation, cyclical unemployment.', 6, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Distinguish demand-pull from cost-push inflation.', 'Demand-pull: AD grows faster than AS, pulling prices up ("too much money chasing too few goods"). Cost-push: rising production costs (wages, oil, import prices) shift SRAS left, raising P and reducing Y (stagflation).', 7, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'How is UK CPI measured and what is the BoE target?', 'CPI tracks the price of a representative basket of around 700 goods/services weighted by household spending; basket updated annually. The Bank of England targets CPI inflation at 2% (symmetric, with letter to Chancellor if more than 1pp away).', 8, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Name the five main types of unemployment.', 'Cyclical (demand-deficient — 2008-09 recession), structural (skills/location mismatch — UK coal, steel, shipbuilding), frictional (between jobs), seasonal (tourism, retail), real-wage/classical (wage above market clearing).', 9, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Distinguish the Claimant Count from the ILO/LFS measure of unemployment.', 'Claimant Count: people receiving unemployment-related benefits — precise but distorted by rule changes and excludes ineligible jobseekers. LFS (ILO): survey of those without work, available, and actively seeking — internationally comparable but lagged.', 10, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Define the natural rate of unemployment (NRU/NAIRU).', 'The unemployment rate when the labour market is in equilibrium — the sum of frictional and structural unemployment with no cyclical component. Consistent with stable inflation; lowering unemployment below it accelerates inflation.', 11, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'List the four components of the current account.', 'Trade in goods, trade in services, primary income (interest, profits, dividends from abroad), secondary income (transfers, e.g. remittances, foreign aid). UK runs a goods deficit but a services surplus, especially financial services from the City.', 12, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'Give two causes of a UK current account deficit.', 'Strong domestic consumer demand sucking in imports; relatively low productivity reducing competitiveness; structural decline of manufacturing; dependence on imported energy; sometimes an overvalued exchange rate.', 13, 'alevel'),
  ('Economics', 'OCR', '2.1', 'National & International Economy', 'State the law of comparative advantage.', 'Ricardo: a country should specialise in goods it can produce at a LOWER OPPORTUNITY COST than other countries. Both partners gain from trade if they specialise according to comparative advantage, even if one has an absolute advantage in everything.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'State the components of AD and their approximate UK weights.', 'AD = C + I + G + (X - M). Roughly: C ≈ 60-65%, I ≈ 16-18%, G ≈ 20%, with net exports (X-M) typically a small negative for the UK.', 1, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Give three reasons the AD curve slopes downward.', 'Real-balance (wealth) effect — higher P erodes real money; interest-rate effect — higher P raises money demand and rates, cutting I; international-trade effect — higher P makes exports dearer and imports cheaper, cutting net exports.', 2, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'List four factors that shift AD right.', 'Higher consumer/business confidence, lower interest rates, income-tax cuts, lower corporation tax, easier credit, sterling depreciation boosting net exports, expansionary fiscal policy, faster growth in trading partners.', 3, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Sketch demand-pull inflation on an AD/AS diagram.', 'AD shifts right along an upward-sloping SRAS: price level rises and real GDP rises. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="2"/><text x="158" y="32" font-size="8" fill="#1a73e8">SRAS</text><line x1="35" y1="35" x2="155" y2="110" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="138" y="115" font-size="8" fill="#dc2626">AD1</text><line x1="65" y1="20" x2="180" y2="105" stroke="#dc2626" stroke-width="2"/><text x="170" y="115" font-size="8" fill="#dc2626">AD2</text><circle cx="92" cy="78" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="65" r="2.5" fill="#0B1E3F"/><line x1="25" y1="78" x2="92" y2="78" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="65" x2="118" y2="65" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="81" font-size="8" fill="#0B1E3F">P1</text><text x="9" y="68" font-size="8" fill="#0B1E3F">P2</text><text x="100" y="135" font-size="9" fill="#0B1E3F">Real GDP</text></svg>', 4, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Sketch cost-push inflation on an AD/AS diagram.', 'SRAS shifts left (e.g. higher oil/wage costs). Price level rises and real GDP falls — stagflation. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="2" stroke-dasharray="4,3"/><text x="160" y="32" font-size="8" fill="#1a73e8">SRAS1</text><line x1="35" y1="80" x2="180" y2="15" stroke="#1a73e8" stroke-width="2"/><text x="160" y="14" font-size="8" fill="#1a73e8">SRAS2</text><line x1="35" y1="25" x2="180" y2="105" stroke="#dc2626" stroke-width="2"/><text x="170" y="112" font-size="8" fill="#dc2626">AD</text><circle cx="100" cy="73" r="2.5" fill="#0B1E3F"/><circle cx="80" cy="62" r="2.5" fill="#0B1E3F"/><line x1="25" y1="73" x2="100" y2="73" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="62" x2="80" y2="62" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="80" y1="62" x2="80" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="100" y1="73" x2="100" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="76" font-size="8" fill="#0B1E3F">P1</text><text x="9" y="65" font-size="8" fill="#0B1E3F">P2</text></svg>', 5, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Sketch the Classical (vertical) LRAS curve.', 'LRAS is vertical at full-employment output Yfe. In the long run, output is determined purely by supply-side factors; AD changes only affect the price level. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="120" y1="20" x2="120" y2="115" stroke="#16a34a" stroke-width="2"/><text x="125" y="25" font-size="8" fill="#16a34a">LRAS</text><line x1="35" y1="30" x2="180" y2="105" stroke="#dc2626" stroke-width="2"/><text x="170" y="112" font-size="8" fill="#dc2626">AD</text><line x1="120" y1="20" x2="120" y2="115" stroke="#16a34a" stroke-width="2"/><text x="115" y="128" font-size="8" fill="#0B1E3F">Yfe</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">P level</text></svg>', 6, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Sketch the Keynesian LRAS curve.', 'Three sections: horizontal at low Y (spare capacity, deflationary gap), upward-sloping (approaching full capacity), vertical at Yfe. AD shifts in the flat section raise output without inflation. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,90 L80,90 Q120,90 140,50 L140,15" fill="none" stroke="#16a34a" stroke-width="2"/><text x="145" y="22" font-size="8" fill="#16a34a">LRAS</text><line x1="35" y1="40" x2="160" y2="105" stroke="#dc2626" stroke-width="2"/><text x="150" y="112" font-size="8" fill="#dc2626">AD</text><text x="135" y="128" font-size="8" fill="#0B1E3F">Yfe</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">P level</text></svg>', 7, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'List four factors that shift LRAS right (long-run growth).', 'More/better-quality labour (immigration, education, training), more/better capital (investment, infrastructure), technological progress, institutional improvements (property rights, deregulation), discovery/efficient use of natural resources.', 8, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'State the multiplier formulae using MPC and MPW.', 'k = 1 / (1 - MPC) = 1 / MPW where MPW = MPS + MPT + MPM. So an injection of £10bn with MPC = 0.6 gives k = 2.5 and final ΔY = £25bn.', 9, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Why is the multiplier larger when MPC is higher?', 'A larger fraction of each round of new income is re-spent rather than withdrawn (saved, taxed, imported). Each successive round of spending creates more income, so the chain of induced spending sums to a bigger total.', 10, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'List three limitations of the multiplier in practice.', 'Higher imports leak demand abroad (high MPM); crowding out (gov borrowing raises rates and squeezes I); inflation if economy near capacity; long lags before effects materialise; supply constraints.', 11, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Distinguish the Classical and Keynesian views of the macroeconomy.', 'Classical/monetarist: economy self-corrects to Yfe; AD changes only inflate prices long run; supply-side policies needed. Keynesian: economy can be stuck below Yfe for long periods; demand-management (fiscal) policy needed in slumps.', 12, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Why does sterling depreciation tend to shift AD right and SRAS left?', 'AD: cheaper exports and dearer imports raise net exports (X-M). SRAS: imported raw materials, components and energy cost more, raising production costs. Net effect on output and inflation depends on which dominates.', 13, 'alevel'),
  ('Economics', 'OCR', '2.2', 'AD/AS & Equilibrium', 'Distinguish actual (short-run) growth from potential (long-run) growth on AD/AS.', 'Actual growth: AD shifts right — uses spare capacity, moves economy toward LRAS. Potential growth: LRAS shifts right — productive capacity rises, allowing higher Y without inflation. PPF analogy: inside vs outward shift.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Who sets UK monetary policy, how often, and what is the inflation target?', 'The Bank of England''s 9-member Monetary Policy Committee (MPC) meets eight times a year. It sets Bank Rate to hit a symmetric CPI inflation target of 2%; the Governor must write to the Chancellor if inflation deviates by more than 1 percentage point.', 1, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Explain the monetary transmission mechanism in two steps.', '(1) Bank Rate change feeds into market rates, asset prices, exchange rate and expectations. (2) These affect C, I, and X-M, shifting AD and so output and inflation. Lags are typically up to 18-24 months.', 2, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'What is quantitative easing (QE)?', 'The central bank creates new reserves to buy government bonds and other assets, raising bond prices and lowering long-term yields. Aim: stimulate AD when Bank Rate is near the zero lower bound. Used after 2008 and during COVID; reversed (QT) from 2022.', 3, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Distinguish expansionary from contractionary fiscal policy.', 'Expansionary: higher G or lower T to boost AD (e.g. £370bn COVID support). Contractionary: lower G or higher T to dampen AD and reduce a budget deficit (e.g. post-2010 austerity).', 4, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Define automatic stabilisers and give two examples.', 'Features of fiscal policy that smooth the cycle without new decisions: in recession, tax revenues fall and benefit spending rises (welfare, jobseekers'' allowance), supporting AD. The reverse happens in booms.', 5, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Distinguish a cyclical from a structural budget deficit.', 'Cyclical: arises from the business cycle (recession depresses revenues, raises spending) — disappears as the economy recovers. Structural: persists at full employment — requires policy action (tax rises, spending cuts) to close.', 6, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Sketch expansionary fiscal policy on an AD/AS diagram.', 'Higher G or lower T shifts AD right (potentially amplified by the multiplier). Output rises; price level rises (size depends on slope of SRAS). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="100" x2="180" y2="35" stroke="#1a73e8" stroke-width="2"/><text x="158" y="32" font-size="8" fill="#1a73e8">SRAS</text><line x1="35" y1="35" x2="155" y2="110" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="138" y="115" font-size="8" fill="#dc2626">AD1</text><line x1="65" y1="20" x2="180" y2="105" stroke="#dc2626" stroke-width="2"/><text x="170" y="115" font-size="8" fill="#dc2626">AD2</text><circle cx="92" cy="78" r="2.5" fill="#0B1E3F"/><circle cx="118" cy="65" r="2.5" fill="#0B1E3F"/><line x1="92" y1="78" x2="92" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="118" y1="65" x2="118" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="86" y="128" font-size="8" fill="#0B1E3F">Y1</text><text x="112" y="128" font-size="8" fill="#0B1E3F">Y2</text></svg>', 7, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Distinguish market-based from interventionist supply-side policies.', 'Market-based: cut income/corporation tax, deregulate, weaken trade unions, privatise, reform welfare. Interventionist: invest in education/training, R&D subsidies, infrastructure (HS2), apprenticeships. Both aim to shift LRAS right but use different means.', 8, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Sketch a successful supply-side policy on the AD/AS diagram.', 'LRAS shifts right; equilibrium output rises and price level falls — improves growth, employment and inflation simultaneously (no Phillips trade-off). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="100" y1="20" x2="100" y2="115" stroke="#16a34a" stroke-width="2" stroke-dasharray="4,3"/><text x="76" y="25" font-size="8" fill="#16a34a">LRAS1</text><line x1="135" y1="20" x2="135" y2="115" stroke="#16a34a" stroke-width="2"/><text x="138" y="25" font-size="8" fill="#16a34a">LRAS2</text><line x1="35" y1="30" x2="180" y2="105" stroke="#dc2626" stroke-width="2"/><text x="170" y="112" font-size="8" fill="#dc2626">AD</text><circle cx="100" cy="64" r="2.5" fill="#0B1E3F"/><circle cx="135" cy="83" r="2.5" fill="#0B1E3F"/><line x1="25" y1="64" x2="100" y2="64" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="83" x2="135" y2="83" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="67" font-size="8" fill="#0B1E3F">P1</text><text x="9" y="86" font-size="8" fill="#0B1E3F">P2</text></svg>', 9, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Sketch the short-run Phillips curve (SRPC).', 'Downward-sloping: lower unemployment is associated with higher inflation (and vice versa) in the short run, reflecting a demand-side trade-off. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q90,55 140,90 Q165,105 180,108" fill="none" stroke="#dc2626" stroke-width="2"/><text x="155" y="40" font-size="8" fill="#dc2626">SRPC</text><text x="100" y="135" font-size="9" fill="#0B1E3F">Unemployment %</text><text x="2" y="78" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,78)">Inflation %</text></svg>', 10, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Sketch the long-run Phillips curve (LRPC).', 'Friedman/Phelps: vertical at the natural rate of unemployment (NRU). Any short-run trade-off is removed once expectations adjust — only NRU is consistent with stable inflation. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M40,30 Q90,55 140,90 Q165,105 180,108" fill="none" stroke="#dc2626" stroke-width="1.8" stroke-dasharray="3,2"/><text x="150" y="40" font-size="8" fill="#dc2626">SRPC</text><line x1="115" y1="20" x2="115" y2="115" stroke="#16a34a" stroke-width="2"/><text x="120" y="25" font-size="8" fill="#16a34a">LRPC</text><text x="103" y="128" font-size="8" fill="#0B1E3F">NRU</text><text x="100" y="138" font-size="8" fill="#0B1E3F">Unemployment</text><text x="2" y="78" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,78)">Inflation %</text></svg>', 11, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Sketch the Laffer curve and explain its policy implication.', 'Inverted U: tax revenue rises with the rate, peaks at t*, then falls as disincentives, evasion and emigration dominate. Implication: cutting tax rates from above t* could raise revenue. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,110 Q105,15 180,110" fill="none" stroke="#dc2626" stroke-width="2"/><circle cx="105" cy="32" r="2.5" fill="#0B1E3F"/><line x1="105" y1="32" x2="105" y2="115" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="100" y="128" font-size="8" fill="#0B1E3F">t*</text><text x="155" y="120" font-size="8" fill="#0B1E3F">100%</text><text x="35" y="120" font-size="8" fill="#0B1E3F">0%</text><text x="100" y="138" font-size="9" fill="#0B1E3F">Tax rate</text><text x="2" y="78" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,78)">Tax revenue</text></svg>', 12, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'List two key macroeconomic policy conflicts.', 'Growth vs inflation (rapid AD growth causes demand-pull inflation); growth vs current account (income rises pull in imports); low unemployment vs inflation (Phillips curve). Inflation vs growth/unemployment is the classic trade-off in cost-push shocks.', 13, 'alevel'),
  ('Economics', 'OCR', '2.3', 'Economic Policy', 'Give two limitations of monetary policy.', 'Long, variable lags (12-24 months); zero lower bound limits cuts in deep recessions; banks may not pass on rate cuts; weak transmission if confidence is low; cost-push inflation cannot be tackled without harming output.', 14, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Distinguish floating, managed and fixed exchange rate systems.', 'Floating: rate set entirely by S&D in the FX market (US dollar, sterling). Managed: floats but central bank intervenes to smooth movements. Fixed: pegged to another currency or basket via intervention or capital controls.', 1, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Distinguish appreciation/depreciation from revaluation/devaluation.', 'Appreciation/depreciation: market-driven changes under a floating regime. Revaluation/devaluation: deliberate policy changes to a fixed peg.', 2, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Sketch a sterling appreciation in the FX market.', 'Higher demand for £ (or lower supply) shifts D right or S left, raising the exchange rate. Causes: higher UK interest rates, FDI inflows, current-account surplus. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="25" x2="180" y2="110" stroke="#dc2626" stroke-width="2" stroke-dasharray="4,3"/><text x="170" y="115" font-size="8" fill="#dc2626">D1</text><line x1="65" y1="25" x2="190" y2="100" stroke="#dc2626" stroke-width="2"/><text x="180" y="98" font-size="8" fill="#dc2626">D2</text><line x1="35" y1="110" x2="180" y2="25" stroke="#1a73e8" stroke-width="2"/><text x="183" y="28" font-size="9" fill="#1a73e8">S</text><circle cx="105" cy="68" r="2.5" fill="#0B1E3F"/><circle cx="125" cy="55" r="2.5" fill="#0B1E3F"/><line x1="25" y1="68" x2="105" y2="68" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><line x1="25" y1="55" x2="125" y2="55" stroke="#64748b" stroke-width="0.7" stroke-dasharray="2,2"/><text x="9" y="71" font-size="8" fill="#0B1E3F">e1</text><text x="9" y="58" font-size="8" fill="#0B1E3F">e2</text><text x="2" y="78" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,78)">£/$</text></svg>', 3, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'State the Marshall-Lerner condition.', 'A currency depreciation improves the current account if the sum of the price elasticities of demand for exports and imports exceeds one (|PEDx| + |PEDm| > 1). Otherwise, depreciation worsens the deficit.', 4, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Sketch the J-curve.', 'After depreciation, the current account WORSENS first (volumes adjust slowly, contracts in old prices) then IMPROVES once Marshall-Lerner holds. Trace from a fall, through a trough, then up beyond the original level. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="80" x2="190" y2="80" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M30,75 Q60,110 90,105 Q140,90 180,30" fill="none" stroke="#1a73e8" stroke-width="2"/><line x1="55" y1="75" x2="55" y2="80" stroke="#dc2626" stroke-width="1.5"/><text x="35" y="73" font-size="7" fill="#dc2626">deprec.</text><text x="100" y="135" font-size="9" fill="#0B1E3F">Time</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">CA balance</text></svg>', 5, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Sketch comparative advantage with a PPF.', 'Two countries with linear PPFs of different slopes; each has a comparative advantage in the good with the lower opportunity cost (steeper line for one good = lower OC of the other). Trade allows consumption beyond the PPF. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="25" x2="100" y2="115" stroke="#1a73e8" stroke-width="2"/><text x="105" y="115" font-size="8" fill="#1a73e8">A</text><line x1="25" y1="65" x2="170" y2="115" stroke="#16a34a" stroke-width="2"/><text x="175" y="115" font-size="8" fill="#16a34a">B</text><text x="2" y="65" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,65)">Good Y</text><text x="100" y="135" font-size="9" fill="#0B1E3F">Good X</text></svg>', 6, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Distinguish a tariff from a quota.', 'Tariff: tax on imports — raises domestic price and generates government revenue. Quota: physical limit on imported quantity — also raises price but the rent goes to whoever holds the import licences. Both create deadweight loss.', 7, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Sketch a tariff on imports showing CS loss, PS gain, gov revenue and DWL.', 'World price line is horizontal; tariff raises it. Domestic supply rises and demand falls; the gap is reduced imports. CS area shrinks; PS gains a slice; government collects tariff x imports; two small triangles are DWL. <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="35" y1="20" x2="180" y2="110" stroke="#dc2626" stroke-width="1.8"/><text x="183" y="113" font-size="9" fill="#dc2626">D</text><line x1="35" y1="110" x2="180" y2="20" stroke="#1a73e8" stroke-width="1.8"/><text x="183" y="22" font-size="9" fill="#1a73e8">S</text><line x1="25" y1="92" x2="180" y2="92" stroke="#16a34a" stroke-width="1.5" stroke-dasharray="3,2"/><text x="155" y="89" font-size="7" fill="#16a34a">Pw</text><line x1="25" y1="78" x2="180" y2="78" stroke="#f59e0b" stroke-width="1.5" stroke-dasharray="3,2"/><text x="148" y="75" font-size="7" fill="#f59e0b">Pw+t</text><line x1="64" y1="92" x2="64" y2="115" stroke="#64748b" stroke-width="0.6" stroke-dasharray="2,2"/><line x1="87" y1="78" x2="87" y2="115" stroke="#64748b" stroke-width="0.6" stroke-dasharray="2,2"/><line x1="128" y1="78" x2="128" y2="115" stroke="#64748b" stroke-width="0.6" stroke-dasharray="2,2"/><line x1="151" y1="92" x2="151" y2="115" stroke="#64748b" stroke-width="0.6" stroke-dasharray="2,2"/><rect x="87" y="78" width="41" height="14" fill="#f59e0b" fill-opacity="0.3"/><polygon points="64,92 87,92 87,78" fill="#dc2626" fill-opacity="0.3"/><polygon points="128,92 151,92 128,78" fill="#dc2626" fill-opacity="0.3"/></svg>', 8, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Give three arguments FOR and three AGAINST protectionism.', 'For: infant industries, strategic/sunset industries, anti-dumping, tackling current-account deficits, retaliating against unfair subsidies. Against: higher consumer prices, retaliation/trade wars, X-inefficiency in protected firms, loss of comparative-advantage gains, distorted resource allocation.', 9, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Distinguish economic growth from economic development.', 'Growth: rise in real GDP. Development: broader — higher incomes plus improvements in health, education, freedom, equality and environmental quality. Sen: development is the expansion of human capabilities and freedoms.', 10, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'List four barriers to economic development in low-income countries.', 'Primary-product dependency and volatile commodity prices, low savings/investment (Harrod-Domar), poor infrastructure, weak human capital (education, health), corruption and weak institutions, debt burdens, civil conflict, capital flight.', 11, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Sketch a Lorenz curve and explain the Gini coefficient.', '45° line = perfect equality. Lorenz curve sags below it; the more it sags, the more unequal the distribution. Gini = area between the two ÷ area under the 45° line, scaled 0 (equality) to 1 (one person owns everything). <svg viewBox="0 0 200 140" width="180" height="125" style="display:block;margin:6px auto"><line x1="25" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="115" x2="180" y2="20" stroke="#16a34a" stroke-width="1.5" stroke-dasharray="3,2"/><text x="150" y="35" font-size="8" fill="#16a34a">Equality</text><path d="M25,115 Q120,100 180,20" fill="none" stroke="#dc2626" stroke-width="2"/><text x="150" y="80" font-size="8" fill="#dc2626">Lorenz</text><text x="100" y="135" font-size="9" fill="#0B1E3F">% population</text><text x="2" y="78" font-size="9" fill="#0B1E3F" transform="rotate(-90,2,78)">% income</text></svg>', 12, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'Distinguish income inequality from wealth inequality.', 'Income: flow over a period (wages, profits, rent, transfers). Wealth: stock of assets at a point in time (housing, pensions, shares). UK wealth inequality is much higher than income inequality — top 10% hold around half of net wealth.', 13, 'alevel'),
  ('Economics', 'OCR', '2.4', 'International Economics & Development', 'List four UK policies to reduce inequality.', 'Progressive income tax, National Living Wage, Universal Credit and other transfers, free state schooling and NHS, taxation of wealth (inheritance tax, capital gains tax), regional/levelling-up policies and skills/training programmes.', 14, 'alevel');
