-- A-Level Economics Flashcards (AQA, Edexcel A, Edexcel B, OCR)
-- Generated for the RAG Learning study app from existing notes HTML files
-- (notes-economics-{board}-alevel/). One INSERT per topic; card_order
-- restarts at 1 within each topic. Inline SVG diagrams are used only on
-- the cards where the diagram IS the answer (supply/demand shifts,
-- AD/AS, monopoly DWL, externality wedge, PPF, Lorenz, etc.) — not on
-- definition or evaluation cards.

-- ---------------------------------------------------------------
-- Schema migration: add 'level' column if not present (idempotent)
-- ---------------------------------------------------------------
ALTER TABLE flashcards ADD COLUMN IF NOT EXISTS level TEXT DEFAULT 'alevel'
  CHECK (level IN ('gcse','as','alevel'));

